45→// Chrome DevTools Protocol Client for source inspection
46→// Handles communication with Chrome's remote debugging interface
47→export class CDPClient {
48→  private port: number
49→  private host: string
50→  private transport: 'websocket' | 'pipe' = 'websocket'
51→  private ws: WebSocket | null = null
52→  private pipeIn: Readable | null = null
53→  private pipeOut: Writable | null = null
54→  private pipeBuffer: Buffer = Buffer.alloc(0)
55→  private targetWebSocketUrl: string | null = null
56→  private eventCallbacks = new Set<(message: Record<string, unknown>) => void>()
57→  private messageId = 0
58→  private pendingRequests = new Map<
59→    number,
60→    {
61→      resolve: Function
62→      reject: Function
63→      timeout?: ReturnType<typeof setTimeout>
64→      method?: string
65→    }
66→  >()
67→  private heartbeatTimer: ReturnType<typeof setInterval> | null = null
68→
69→  constructor(port: number = 9222, host: string = '127.0.0.1') {
70→    this.port = port
71→    this.host = host
72→  }
73→
74→  private isDev() {
75→    return process.env.EXTENSION_AUTHOR_MODE === 'true'
76→  }
77→
78→  async connect(): Promise<void> {
79→    return new Promise(async (resolve, reject) => {
80→      try {
81→        this.targetWebSocketUrl = await discoverWebSocketDebuggerUrl(
82→          this.host,
83→          this.port,
84→          this.isDev()
85→        )
86→
87→        let pendingRejected = false
88→        this.ws = await establishBrowserConnection(
89→          this.targetWebSocketUrl!,
90→          this.isDev(),
91→          (data) => this.handleMessage(data),
92→          (reason) => {
93→            // Guard against double-rejection (error + close fire in sequence)
94→            if (pendingRejected) return
95→
96→            pendingRejected = true
97→            // Reject any pending requests to avoid hangs
98→            this.pendingRequests.forEach(({reject, timeout}, id) => {
99→              try {
100→                reject(new Error(reason))
101→              } catch (error) {
102→                if (this.isDev()) {
103→                  const err = error as Error
104→                  console.warn(
105→                    messages.cdpPendingRejectFailed(String(err.message || err))
106→                  )
107→                }
108→              }
109→
110→              if (timeout) clearTimeout(timeout)
111→              this.pendingRequests.delete(id)
112→            })
113→            // Mark ws as dead so sendCommand rejects immediately
114→            this.ws = null
115→          }
116→        )
117→
118→        this.transport = 'websocket'
119→        this.startHeartbeat()
120→
121→        if (this.isDev()) {
122→          console.log(messages.cdpClientConnected(this.host, this.port))
123→        }
124→
125→        resolve()
126→      } catch (error) {
127→        const err = error as Error
128→        reject(new Error(`Failed to connect to CDP: ${err.message || err}`))
129→      }
130→    })
131→  }
132→
133→  async connectViaPipe(input: Readable, output: Writable): Promise<void> {
134→    this.transport = 'pipe'
135→    this.pipeIn = input
136→    this.pipeOut = output
137→    this.pipeBuffer = Buffer.alloc(0)
138→
139→    input.on('data', (chunk: Buffer) => {
140→      this.pipeBuffer = Buffer.concat([this.pipeBuffer, chunk])
141→      let idx: number
142→
143→      while ((idx = this.pipeBuffer.indexOf(0)) !== -1) {
144→        const msg = this.pipeBuffer.subarray(0, idx).toString('utf-8')
145→        this.pipeBuffer = this.pipeBuffer.subarray(idx + 1)
146→        this.handleMessage(msg)
147→      }
148→    })
149→
150→    input.on('error', (error: Error) => {
151→      if (this.isDev()) {
152→        console.error(`[CDP] Pipe read error: ${error.message}`)
153→      }
154→
155→      this.rejectAllPending('CDP pipe read error')
156→    })
157→
158→    input.on('close', () => {
159→      if (this.isDev()) console.log('[CDP] Pipe closed')
160→
161→      this.rejectAllPending('CDP pipe closed')
162→      this.pipeIn = null
163→    })
164→
165→    this.startHeartbeat()
166→
167→    if (this.isDev()) {
168→      console.log(messages.cdpClientConnected(this.host, this.port))
169→    }
170→  }
171→
172→  private rejectAllPending(reason: string) {
173→    this.pendingRequests.forEach(({reject, timeout}, id) => {
174→      try {
175→        reject(new Error(reason))
176→      } catch {
177→        // ignore
178→      }
179→
180→      if (timeout) clearTimeout(timeout)
181→      this.pendingRequests.delete(id)
182→    })
183→  }
184→
185→  disconnect() {
186→    this.stopHeartbeat()
187→
188→    if (this.transport === 'pipe') {
189→      try {
190→        this.pipeIn?.removeAllListeners()
191→        this.pipeOut?.end()
192→      } catch {
193→        // ignore
194→      }
195→      this.pipeIn = null
196→      this.pipeOut = null
197→    }
198→
199→    if (this.ws) {
200→      try {
201→        this.ws.close()
202→      } catch {
203→        // ignore
204→      }
205→      this.ws = null
206→    }
207→  }
208→
209→  private startHeartbeat() {
210→    this.stopHeartbeat()
211→    this.heartbeatTimer = setInterval(async () => {
212→      if (!this.isConnected()) {
213→        this.stopHeartbeat()
214→        return
215→      }
216→
217→      try {
218→        await this.getBrowserVersion()
219→      } catch {
220→        // Heartbeat failure — connection is dead, disconnect to trigger cleanup
221→        if (this.isDev()) {
222→          console.warn('[CDP] Heartbeat failed, connection appears dead')
223→        }
224→        this.disconnect()
225→      }
226→    }, CDP_HEARTBEAT_INTERVAL_MS)
227→
228→    if (typeof this.heartbeatTimer.unref === 'function') {
229→      this.heartbeatTimer.unref()
230→    }
231→  }
232→
233→  private stopHeartbeat() {
234→    if (this.heartbeatTimer) {
235→      clearInterval(this.heartbeatTimer)
236→      this.heartbeatTimer = null
237→    }
238→  }
239→
240→  isConnected(): boolean {
241→    if (this.transport === 'pipe') {
242→      return (
243→        !!this.pipeIn &&
244→        !this.pipeIn.destroyed &&
245→        !!this.pipeOut &&
246→        !this.pipeOut.destroyed
247→      )
248→    }
249→
250→    return !!this.ws && this.ws.readyState === WebSocket.OPEN
251→  }
252→
253→  onProtocolEvent(handler: (message: Record<string, unknown>) => void) {
254→    this.eventCallbacks.add(handler)
255→
256→    return () => {
257→      this.eventCallbacks.delete(handler)
258→    }
259→  }
260→
261→  private handleMessage(data: string) {
262→    try {
263→      const message = JSON.parse(data)
264→
265→      if (message.id) {
266→        const pending = this.pendingRequests.get(message.id)
267→
268→        if (pending) {
269→          if (pending.timeout) {
270→            clearTimeout(pending.timeout)
271→          }
272→
273→          this.pendingRequests.delete(message.id)
274→
275→          if (message.error) {
276→            pending.reject(new Error(JSON.stringify(message.error)))
277→          } else {
278→            pending.resolve(message.result)
279→          }
280→        }
281→
282→        return
283→      }
284→
285→      if (message.method === 'Target.attachedToTarget') {
286→        const params = message.params || {}
287→
288→        if (this.isDev()) {
289→          console.log(
290→            messages.cdpClientAttachedToTarget(
291→              String(params.sessionId || ''),
292→              String(params.targetInfo?.type || '')
293→            )
294→          )
295→        }
296→      }
297→
298→      for (const eventCallback of this.eventCallbacks) {
299→        eventCallback(message)
300→      }
301→    } catch (error) {
302→      if (this.isDev()) {
303→        const err = error as Error
304→        console.warn(
305→          messages.cdpFailedToHandleMessage(String(err.message || err))
306→        )
307→      }
308→    }
309→  }
310→
311→  // Send a command to the CDP endpoint
312→  async sendCommand(
313→    method: string,
314→    params: Record<string, unknown> = {},
315→    sessionId?: string,
316→    timeoutMs: number = CDP_COMMAND_TIMEOUT_MS
317→  ): Promise<unknown> {
318→    return new Promise((resolve, reject) => {
319→      if (!this.isConnected()) {
320→        return reject(new Error('CDP transport is not open'))
321→      }
322→
323→      const id = ++this.messageId
324→      const message: Record<string, unknown> = {id, method, params}
325→      if (sessionId) message.sessionId = sessionId
326→
327→      try {
328→        const timeout = setTimeout(() => {
329→          const pending = this.pendingRequests.get(id)
330→          if (!pending) return
331→
332→          this.pendingRequests.delete(id)
333→
334→          pending.reject(
335→            new Error(
336→              `CDP command timed out (${timeoutMs}ms): ${String(
337→                pending.method || method
338→              )}`
339→            )
340→          )
341→        }, timeoutMs)
342→
343→        this.pendingRequests.set(id, {resolve, reject, timeout, method})
344→
345→        const data = JSON.stringify(message)
346→        if (this.transport === 'pipe' && this.pipeOut) {
347→          this.pipeOut.write(data + '\0')
348→        } else if (this.ws) {
349→          this.ws.send(data)
350→        }
351→      } catch (error) {
352→        const pending = this.pendingRequests.get(id)
353→
354→        if (pending?.timeout) {
355→          clearTimeout(pending.timeout)
356→        }
357→
358→        this.pendingRequests.delete(id)
359→        reject(error)
360→      }
361→    })
362→  }
