584→  // Extension Management Methods
585→  async forceReloadExtension(extensionId: string) {
586→    // Safety first: avoid Extensions.reload(forceReload), which can disable
587→    // or relocate unpacked extensions in fresh Chromium profiles during
588→    // automation. Keep reloads extension-owned via runtime.reload().
589→    const attempts = 8
590→    let lastError: unknown = null
591→    for (let i = 0; i < attempts; i++) {
592→      try {
593→        const ok = await this.reloadExtensionViaTargetEval(extensionId)
594→        if (ok) return true
595→      } catch (error) {
596→        lastError = error
597→      }
598→      const backoffMs = Math.min(1200, 150 * (i + 1))
599→      await new Promise((r) => setTimeout(r, backoffMs))
600→    }
601→    console.warn(
602→      messages.cdpClientExtensionReloadFailed(
603→        extensionId,
604→        (lastError as Error)?.message ||
605→          String(lastError || 'runtime.reload failed')
606→      )
607→    )
608→    return false
609→  }
610→
611→  async getExtensionInfo(extensionId: string) {
612→    try {
613→      return await getExtensionInfo(this, extensionId)
614→    } catch (error) {
615→      throw new Error(
616→        messages.cdpClientExtensionInfoFailed(
617→          extensionId,
618→          (error as Error).message
619→        )
620→      )
621→    }
622→  }
623→
624→  private async reloadExtensionViaTargetEval(extensionId: string) {
625→    try {
626→      const targets = await this.getTargets()
627→      const preferredOrder = [
628→        'service_worker',
629→        'background_page',
630→        'worker',
631→        'page'
632→      ]
633→
634→      for (const type of preferredOrder) {
635→        const matchingTargets = (targets || []).filter(
636→          (t: Record<string, unknown>) => {
637→            const url: string = String((t as any)?.url || '')
638→            const tt: string = String((t as any)?.type || '')
639→            const inExtensionScope = url.startsWith(
640→              `chrome-extension://${extensionId}/`
641→            )
642→
643→            return tt === type && inExtensionScope
644→          }
645→        )
646→
647→        for (const target of matchingTargets) {
648→          const targetId: string | undefined = (target as any)?.targetId
649→
650→          if (!targetId) continue
651→
652→          let sessionId: string
653→          try {
654→            sessionId = await this.attachToTarget(targetId)
655→          } catch {
656→            // ignore and try next target
657→            continue
658→          }
659→
660→          try {
661→            await this.sendCommand('Runtime.enable', {}, sessionId)
662→          } catch {
663→            // Runtime.enable can race with SW termination; don't retry
664→            // by re-attaching to a sibling target — that would dispatch a
665→            // second chrome.runtime.reload() and the user would see the
666→            // extension flash twice. Treat the reload as fired and let the
667→            // outer hardReload caller wait on the SW restart event instead.
668→            return true
669→          }
670→
671→          // Fire chrome.runtime.reload() and DO NOT await the response.
672→          // Awaiting races with SW termination: if the worker dies before
673→          // CDP returns the evaluate result, the await throws, the catch
674→          // walks to the next matching target, and we re-issue the reload
675→          // there — the user sees the extension reload N times in a row
676→          // (one flash per matching target). Send the command once and
677→          // trust Chrome to honor it.
678→          this.sendCommand(
679→            'Runtime.evaluate',
680→            {
681→              expression:
682→                '(function(){ try { if (!chrome || !chrome.runtime || !chrome.runtime.reload) return false; chrome.runtime.reload(); return true; } catch (error) { return false; } })()',
683→              returnByValue: true
684→            },
685→            sessionId
686→          ).catch(() => {
687→            // SW likely terminated mid-response; expected, no follow-up.
688→          })
689→          return true
690→        }
691→      }
692→      return false
693→    } catch {
694→      return false
695→    }
696→  }
697→
