78→  async connect(): Promise<void> {
79→    return new Promise(async (resolve, reject) => {
80→      try {
81→        this.targetWebSocketUrl = await discoverWebSocketDebuggerUrl(
82→          this.host,
83→          this.port,
84→          this.isDev()
85→        )
86→
87→        let pendingRejected = false
88→        this.ws = await establishBrowserConnection(
89→          this.targetWebSocketUrl!,
90→          this.isDev(),
91→          (data) => this.handleMessage(data),
92→          (reason) => {
93→            // Guard against double-rejection (error + close fire in sequence)
94→            if (pendingRejected) return
95→
96→            pendingRejected = true
97→            // Reject any pending requests to avoid hangs
98→            this.pendingRequests.forEach(({reject, timeout}, id) => {
99→              try {
100→                reject(new Error(reason))
101→              } catch (error) {
102→                if (this.isDev()) {
103→                  const err = error as Error
104→                  console.warn(
105→                    messages.cdpPendingRejectFailed(String(err.message || err))
106→                  )
107→                }
108→              }
109→
110→              if (timeout) clearTimeout(timeout)
111→              this.pendingRequests.delete(id)
112→            })
113→            // Mark ws as dead so sendCommand rejects immediately
114→            this.ws = null
115→          }
116→        )
117→
118→        this.transport = 'websocket'
119→        this.startHeartbeat()
120→
121→        if (this.isDev()) {
122→          console.log(messages.cdpClientConnected(this.host, this.port))
123→        }
124→
125→        resolve()
126→      } catch (error) {
127→        const err = error as Error
128→        reject(new Error(`Failed to connect to CDP: ${err.message || err}`))
129→      }
130→    })
131→  }
