133→  async connectViaPipe(input: Readable, output: Writable): Promise<void> {
134→    this.transport = 'pipe'
135→    this.pipeIn = input
136→    this.pipeOut = output
137→    this.pipeBuffer = Buffer.alloc(0)
138→
139→    input.on('data', (chunk: Buffer) => {
140→      this.pipeBuffer = Buffer.concat([this.pipeBuffer, chunk])
141→      let idx: number
142→
143→      while ((idx = this.pipeBuffer.indexOf(0)) !== -1) {
144→        const msg = this.pipeBuffer.subarray(0, idx).toString('utf-8')
145→        this.pipeBuffer = this.pipeBuffer.subarray(idx + 1)
146→        this.handleMessage(msg)
147→      }
148→    })
149→
150→    input.on('error', (error: Error) => {
151→      if (this.isDev()) {
152→        console.error(`[CDP] Pipe read error: ${error.message}`)
153→      }
154→
155→      this.rejectAllPending('CDP pipe read error')
156→    })
157→
158→    input.on('close', () => {
159→      if (this.isDev()) console.log('[CDP] Pipe closed')
160→
161→      this.rejectAllPending('CDP pipe closed')
162→      this.pipeIn = null
163→    })
164→
165→    this.startHeartbeat()
166→
167→    if (this.isDev()) {
168→      console.log(messages.cdpClientConnected(this.host, this.port))
169→    }
170→  }
