185→  disconnect() {
186→    this.stopHeartbeat()
187→
188→    if (this.transport === 'pipe') {
189→      try {
190→        this.pipeIn?.removeAllListeners()
191→        this.pipeOut?.end()
192→      } catch {
193→        // ignore
194→      }
195→      this.pipeIn = null
196→      this.pipeOut = null
197→    }
198→
199→    if (this.ws) {
