240→  isConnected(): boolean {
241→    if (this.transport === 'pipe') {
242→      return (
243→        !!this.pipeIn &&
244→        !this.pipeIn.destroyed &&
245→        !!this.pipeOut &&
246→        !this.pipeOut.destroyed
247→      )
