261→  private handleMessage(data: string) {
262→    try {
263→      const message = JSON.parse(data)
264→
265→      if (message.id) {
266→        const pending = this.pendingRequests.get(message.id)
267→
268→        if (pending) {
269→          if (pending.timeout) {
270→            clearTimeout(pending.timeout)
271→          }
272→
273→          this.pendingRequests.delete(message.id)
274→
275→          if (message.error) {
276→            pending.reject(new Error(JSON.stringify(message.error)))
277→          } else {
278→            pending.resolve(message.result)
279→          }
280→        }
281→
282→        return
283→      }
284→
285→      if (message.method === 'Target.attachedToTarget') {
286→        const params = message.params || {}
287→
288→        if (this.isDev()) {
289→          console.log(
290→            messages.cdpClientAttachedToTarget(
291→              String(params.sessionId || ''),
292→              String(params.targetInfo?.type || '')
293→            )
294→          )
295→        }
296→      }
297→
298→      for (const eventCallback of this.eventCallbacks) {
299→        eventCallback(message)
300→      }
301→    } catch (error) {
302→      if (this.isDev()) {
303→        const err = error as Error
304→        console.warn(
305→          messages.cdpFailedToHandleMessage(String(err.message || err))
306→        )
307→      }
308→    }
309→  }
