311→  // Send a command to the CDP endpoint
312→  async sendCommand(
313→    method: string,
314→    params: Record<string, unknown> = {},
315→    sessionId?: string,
316→    timeoutMs: number = CDP_COMMAND_TIMEOUT_MS
317→  ): Promise<unknown> {
318→    return new Promise((resolve, reject) => {
319→      if (!this.isConnected()) {
320→        return reject(new Error('CDP transport is not open'))
321→      }
322→
323→      const id = ++this.messageId
324→      const message: Record<string, unknown> = {id, method, params}
325→      if (sessionId) message.sessionId = sessionId
326→
327→      try {
328→        const timeout = setTimeout(() => {
329→          const pending = this.pendingRequests.get(id)
330→          if (!pending) return
331→
332→          this.pendingRequests.delete(id)
333→
334→          pending.reject(
335→            new Error(
336→              `CDP command timed out (${timeoutMs}ms): ${String(
337→                pending.method || method
338→              )}`
339→            )
340→          )
341→        }, timeoutMs)
342→
343→        this.pendingRequests.set(id, {resolve, reject, timeout, method})
344→
345→        const data = JSON.stringify(message)
346→        if (this.transport === 'pipe' && this.pipeOut) {
347→          this.pipeOut.write(data + '\0')
348→        } else if (this.ws) {
349→          this.ws.send(data)
350→        }
351→      } catch (error) {
352→        const pending = this.pendingRequests.get(id)
353→
354→        if (pending?.timeout) {
355→          clearTimeout(pending.timeout)
356→        }
357→
358→        this.pendingRequests.delete(id)
359→        reject(error)
360→      }
361→    })
362→  }
