521→      {depth: -1, pierce: true},
522→      sessionId
523→    )) as {root?: unknown}
524→
525→    const found: Array<{nodeId: number; host: string}> = []
526→    const walk = (node: any, hostName: string): void => {
527→      if (!node || typeof node !== 'object') return
528→      const name = node.localName || node.nodeName || hostName
529→      if (Array.isArray(node.shadowRoots)) {
530→        for (const sr of node.shadowRoots) {
531→          if (
532→            sr &&
533→            sr.shadowRootType === 'closed' &&
534→            typeof sr.nodeId === 'number'
535→          ) {
536→            found.push({nodeId: sr.nodeId, host: String(name)})
537→          }
538→          walk(sr, name)
539→        }
540→      }
541→      if (Array.isArray(node.children))
542→        for (const c of node.children) walk(c, name)
543→      if (node.contentDocument) walk(node.contentDocument, name)
544→    }
545→    walk((doc as any).root, 'html')
546→
547→    const out: Array<{
548→      host: string
549→      type: string
550→      html: string
551→      truncated?: boolean
552→    }> = []
553→    for (const f of found) {
554→      try {
555→        const oh = (await this.sendCommand(
556→          'DOM.getOuterHTML',
557→          {nodeId: f.nodeId},
558→          sessionId
559→        )) as {outerHTML?: string}
560→        let html = String(oh?.outerHTML ?? '')
561→        let truncated = false
562→        if (maxBytes > 0 && html.length > maxBytes) {
563→          html = html.slice(0, maxBytes)
564→          truncated = true
565→        }
566→        out.push({
567→          host: f.host,
568→          type: 'closed',
569→          html,
570→          ...(truncated ? {truncated} : {})
571→        })
572→      } catch {
573→        out.push({host: f.host, type: 'closed', html: ''})
574→      }
575→    }
576→    return out
