1538→  private async collectExecutionContexts(sessionId: string): Promise<any[]> {
1539→    if (!this.cdp) return []
1540→
1541→    const cached = this.sessionContexts.get(sessionId)
1542→    if (cached) return Array.from(cached.values())
1543→
1544→    // First call for this session: install a persistent listener so subsequent
1545→    // rule iterations see the same contexts without needing Runtime.enable to
1546→    // re-emit them (it only emits existing contexts on the first enable).
1547→    const contextsById = new Map<number, unknown>()
1548→    this.sessionContexts.set(sessionId, contextsById)
1549→
