1553→      ) {
1554→        return
1555→      }
1556→      const method = String(message.method || '')
1557→      if (method === 'Runtime.executionContextCreated') {
1558→        const context = (message as {params?: {context?: any}}).params?.context
1559→        const contextId = context?.id
1560→        if (typeof contextId === 'number') {
1561→          contextsById.set(contextId, context)
1562→        }
1563→        return
1564→      }
1565→      if (method === 'Runtime.executionContextDestroyed') {
1566→        const params =
1567→          (message as {params?: {executionContextId?: number}}).params || {}
1568→        if (typeof params.executionContextId === 'number') {
1569→          contextsById.delete(params.executionContextId)
1570→        }
1571→        return
1572→      }
1573→
1574→      if (method === 'Runtime.executionContextsCleared') {
1575→        contextsById.clear()
1576→      }
1577→    })
1578→
1579→    this.sessionContextsUnsubscribe.set(sessionId, unsubscribe)
1580→
1581→    await this.cdp.sendCommand('Runtime.enable', {}, sessionId)
1582→
