1224→  private async reinjectContentScriptRule(
1225→    sessionId: string,
1226→    rule: ContentScriptTargetRule,
1227→    allowCoarseCleanup: boolean,
1228→    sourceOverridesByBundleId?: Record<string, string>
1229→  ): Promise<boolean> {
1230→    if (!this.cdp) return false
1231→
1232→    const bundleId = getCanonicalContentScriptEntryName(rule.index)
1233→    const bundlePath = resolveEmittedContentScriptFile(
1234→      this.outPath,
1235→      rule.index,
1236→      'js'
1237→    )
1238→
1239→    if (!bundlePath || !fs.existsSync(bundlePath)) return false
1240→
1241→    const sourceOverride =
1242→      sourceOverridesByBundleId && typeof sourceOverridesByBundleId === 'object'
1243→        ? sourceOverridesByBundleId[bundleId]
1244→        : undefined
1245→    const source = this.patchReinjectSourceForInvalidatedRuntime(
1246→      typeof sourceOverride === 'string'
1247→        ? sourceOverride
1248→        : readTextFileCached(bundlePath)
1249→    )
1250→    const buildTokenMatch = source.match(
1251→      /__EXTENSIONJS_REINJECT_BUILD_TOKEN\s*=\s*"([^"]+)"/
1252→    )
1253→    const proofMatch =
1254→      source.match(
1255→        /extjs-chromium-live-content-css-modules:script-primary-\d+/
1256→      ) || source.match(/Live Update Proof [A-Za-z0-9_-]+/)
1257→
1258→    if (!source.trim()) return false
1259→    if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
1260→      console.log(
1261→        `[CDP] reinject bundle ${bundleId} from ${bundlePath}` +
1262→          `${proofMatch ? ` (${proofMatch[0]})` : ''}` +
1263→          ` build=${buildTokenMatch?.[1] || '<none>'}` +
1264→          ` sourceOverride=${typeof sourceOverride === 'string'}`
1265→      )
1266→    }
1267→    const contextId = await this.resolveExecutionContextId(sessionId, rule)
1268→    if (!contextId) {
1269→      if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
1270→        console.warn(
1271→          `[CDP] No execution context found for ${bundleId} (${rule.world})`
1272→        )
1273→      }
1274→      return false
1275→    }
1276→
1277→    const result = await this.cdp.evaluateInContext(
1278→      sessionId,
1279→      this.buildReinjectExpression(bundleId, source, allowCoarseCleanup),
1280→      contextId
1281→    )
1282→
1283→    if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
1284→      console.log(
1285→        `[CDP] reinject result ${bundleId}: ${JSON.stringify(result)}`
1286→      )
1287→    }
