1295→  private buildReinjectExpression(
1296→    bundleId: string,
1297→    source: string,
1298→    allowCoarseCleanup: boolean
1299→  ): string {
1300→    const annotatedSource = `${source}\n//# sourceURL=extension.js-reinject://${bundleId}.js`
1301→    const extensionBase = this.extensionId
1302→      ? `chrome-extension://${this.extensionId}/`
1303→      : ''
1304→    return `(() => {
1305→  const bundleId = ${JSON.stringify(bundleId)};
1306→  const source = ${JSON.stringify(annotatedSource)};
1307→  const extensionBase = ${JSON.stringify(extensionBase)};
1308→  const rootSelector = '[data-extension-root], #extension-root';
1309→  const keyedSelector = '[data-extjs-reinject-key="${bundleId}"]';
1310→  const registry = (typeof globalThis === 'object' && globalThis)
1311→    ? (globalThis.__EXTENSIONJS_DEV_REINJECT__ || (globalThis.__EXTENSIONJS_DEV_REINJECT__ = {}))
1312→    : {};
1313→  const existing = registry[bundleId];
1314→  const readGeneration = (entry) => {
1315→    try {
1316→      if (!entry) return 0;
1317→      if (typeof entry === 'function' && typeof entry.__extjsGeneration === 'number') {
1318→        return entry.__extjsGeneration;
1319→      }
1320→      if (typeof entry === 'object') {
1321→        if (typeof entry.__extjsGeneration === 'number') return entry.__extjsGeneration;
1322→        if (typeof entry.generation === 'number') return entry.generation;
1323→        if (typeof entry.cleanup === 'function' && typeof entry.cleanup.__extjsGeneration === 'number') {
1324→          return entry.cleanup.__extjsGeneration;
1325→        }
1326→      }
1327→    } catch (error) {}
1328→    return 0;
1329→  };
1330→  const previousGeneration = readGeneration(existing);
1331→  try {
1332→    if (typeof existing === 'function') existing();
1333→    if (existing && typeof existing.cleanup === 'function') existing.cleanup();
1334→  } catch (error) {}
1335→  if (${allowCoarseCleanup ? 'true' : 'false'}) {
1336→    // Bundle-scoped sweep: only remove roots owned by this bundleId. The inner
1337→    // wrapper tags every host with data-extjs-reinject-key on mount, so this
1338→    // catches roots from a manifest-cached run before the outer cleanup
1339→    // registry was populated. A broad querySelector('[data-extension-root]')
1340→    // would destroy roots owned by sibling content_scripts entries that
1341→    // didn't change — leaving the page with only this bundle's roots.
1342→    try {
1343→      const staleKeyed = Array.from(document.querySelectorAll(keyedSelector));
1344→      for (const root of staleKeyed) {
1345→        if (root && typeof root.remove === 'function') root.remove();
1346→      }
1347→    } catch (error) {}
1348→  }
1349→  const trackedNodes = new Set();
1350→  const trackNode = (node) => {
1351→    try {
1352→      if (!node || typeof Element !== 'function' || !(node instanceof Element)) return;
1353→      const matchesRoot = typeof node.matches === 'function' && node.matches(rootSelector);
1354→      if (!matchesRoot) return;
1355→      trackedNodes.add(node);
1356→      if (typeof node.setAttribute === 'function') {
1357→        node.setAttribute('data-extjs-reinject-key', bundleId);
1358→      }
1359→    } catch (error) {}
1360→  };
1361→  const trackTree = (node) => {
1362→    trackNode(node);
1363→    try {
1364→      if (!node || typeof node.querySelectorAll !== 'function') return;
1365→      const nested = node.querySelectorAll(rootSelector);
1366→      for (const nestedNode of nested) trackNode(nestedNode);
1367→    } catch (error) {}
1368→  };
1369→  const observer = typeof MutationObserver === 'function'
1370→    ? new MutationObserver((mutations) => {
1371→        for (const mutation of mutations) {
1372→          const addedNodes = Array.from(mutation.addedNodes || []);
1373→          for (const addedNode of addedNodes) {
1374→            trackTree(addedNode);
1375→          }
1376→        }
1377→      })
1378→    : null;
1379→  try {
1380→    if (observer && document && document.documentElement) {
1381→      observer.observe(document.documentElement, {childList: true, subtree: true});
1382→    }
1383→  } catch (error) {}
1384→  const cleanupTrackedNodes = () => {
1385→    try {
1386→      if (observer) observer.disconnect();
1387→    } catch (error) {}
1388→    try {
1389→      const keyedNodes = Array.from(document.querySelectorAll(keyedSelector));
1390→      for (const keyedNode of keyedNodes) {
1391→        if (keyedNode && typeof keyedNode.remove === 'function') keyedNode.remove();
1392→      }
1393→    } catch (error) {}
1394→    try {
1395→      for (const trackedNode of trackedNodes) {
1396→        if (trackedNode && trackedNode.isConnected && typeof trackedNode.remove === 'function') {
1397→          trackedNode.remove();
1398→        }
1399→      }
1400→    } catch (error) {}
1401→  };
1402→  registry[bundleId] = {
1403→    cleanup: cleanupTrackedNodes,
1404→    generation: previousGeneration,
1405→    __extjsGeneration: previousGeneration
1406→  };
1407→  try {
1408→    if (typeof globalThis === 'object' && globalThis && extensionBase) {
1409→      globalThis.__EXTJS_EXTENSION_BASE__ = extensionBase;
1410→    }
1411→    if (typeof document === 'object' && document && document.documentElement && extensionBase) {
1412→      document.documentElement.setAttribute('data-extjs-extension-base', extensionBase);
1413→    }
1414→    (0, eval)(source);
1415→  } catch (error) {
1416→    return {
1417→      ok: false,
1418→      error: String((error && error.stack) || (error && error.message) || error || 'unknown'),
1419→      trackedRoots: trackedNodes.size,
1420→      existingRootCount: (() => {
1421→        try { return document.querySelectorAll(rootSelector).length; } catch (innerError) { return -1; }
1422→      })()
1423→    };
1424→  }
1425→  setTimeout(() => {
1426→    try {
1427→      const keyedNodes = Array.from(document.querySelectorAll(keyedSelector));
1428→      for (const keyedNode of keyedNodes) trackedNodes.add(keyedNode);
1429→    } catch (error) {}
1430→  }, 0);
1431→  setTimeout(() => {
1432→    try {
1433→      if (observer) observer.disconnect();
1434→    } catch (error) {}
1435→  }, 2000);
1436→  return {
1437→    ok: true,
1438→    trackedRoots: trackedNodes.size,
1439→    existingRootCount: (() => {
1440→      try { return document.querySelectorAll(rootSelector).length; } catch (innerError) { return -1; }
1441→    })(),
1442→    liveRoots: (() => {
1443→      try {
1444→        return Array.from(document.querySelectorAll(rootSelector)).map((node) => ({
1445→          key: node && typeof node.getAttribute === 'function' ? node.getAttribute('data-extjs-reinject-key') || null : null,
1446→          root: node && typeof node.getAttribute === 'function' ? node.getAttribute('data-extension-root') || null : null,
1447→          build: node && typeof node.getAttribute === 'function' ? node.getAttribute('data-extjs-reinject-build') || null : null,
1448→          text: String(node && node.textContent || '').slice(0, 120)
1449→        }));
1450→      } catch (error) {
1451→        return [];
1452→      }
1453→    })(),
1454→    hasChromeRuntime: (() => {
1455→      try { return !!(globalThis && globalThis.chrome && globalThis.chrome.runtime); } catch (error) { return false; }
1456→    })()
1457→  };
1458→})()`
1459→  }
