1461→  private patchReinjectSourceForInvalidatedRuntime(source: string): string {
1462→    return source.replace(
1463→      '__webpack_require__.p = __webpack_require__.webExtRt.runtime.getURL("/");',
1464→      [
1465→        'try {',
1466→        '  __webpack_require__.p = __webpack_require__.webExtRt.runtime.getURL("/");',
1467→        '} catch (_extjsRuntimeError) {',
1468→        '  if (__extjsBase) {',
1469→        '    __webpack_require__.p = __extjsBase.replace(/\\/+$/, "/") + String("/").replace(/^\\/+/, "");',
1470→        '  } else {',
1471→        '    __webpack_require__.p = "";',
1472→        '  }',
1473→        '}'
1474→      ].join('\n')
