1478→  private async resolveExecutionContextId(
1479→    sessionId: string,
1480→    rule: ContentScriptTargetRule
1481→  ): Promise<number | undefined> {
1482→    if (!this.cdp) return undefined
1483→
1484→    const frameId = await this.getTopFrameId(sessionId)
1485→    const contexts = await this.collectExecutionContexts(sessionId)
1486→
1487→    if (rule.world === 'main') {
1488→      const defaultContext = contexts.find((context) => {
1489→        const auxData = context?.auxData || {}
1490→        return (
1491→          auxData.type === 'default' &&
1492→          auxData.isDefault === true &&
1493→          (!frameId || !auxData.frameId || String(auxData.frameId) === frameId)
1494→        )
1495→      })
1496→      return typeof defaultContext?.id === 'number'
1497→        ? defaultContext.id
1498→        : undefined
1499→    }
1500→
1501→    const extensionId =
1502→      this.extensionId || (await this.deriveExtensionIdFromTargets())
1503→    if (!extensionId) return undefined
1504→
1505→    const extensionOrigin = `chrome-extension://${extensionId}`
1506→    const isolatedContext = contexts.find((context) => {
1507→      const auxData = context?.auxData || {}
1508→      return (
1509→        auxData.type === 'isolated' &&
1510→        String(context?.origin || '') === extensionOrigin &&
1511→        (!frameId || !auxData.frameId || String(auxData.frameId) === frameId)
1512→      )
1513→    })
1514→
1515→    return typeof isolatedContext?.id === 'number'
1516→      ? isolatedContext.id
1517→      : undefined
1518→  }
