1520→  private async getTopFrameId(sessionId: string): Promise<string | undefined> {
1521→    if (!this.cdp) return undefined
1522→
1523→    try {
1524→      const frameTree = (await this.cdp.sendCommand(
1525→        'Page.getFrameTree',
1526→        {},
1527→        sessionId
1528→      )) as {
1529→        frameTree?: {frame?: {id?: string}}
1530→      }
1531→      const frameId = frameTree?.frameTree?.frame?.id
1532→      return typeof frameId === 'string' && frameId ? frameId : undefined
1533→    } catch {
1534→      return undefined
1535→    }
1536→  }
