1538→  private async collectExecutionContexts(sessionId: string): Promise<any[]> {
1539→    if (!this.cdp) return []
1540→
1541→    const cached = this.sessionContexts.get(sessionId)
1542→    if (cached) return Array.from(cached.values())
1543→
1544→    // First call for this session: install a persistent listener so subsequent
1545→    // rule iterations see the same contexts without needing Runtime.enable to
1546→    // re-emit them (it only emits existing contexts on the first enable).
1547→    const contextsById = new Map<number, unknown>()
1548→    this.sessionContexts.set(sessionId, contextsById)
1549→
1550→    const unsubscribe = this.cdp.onProtocolEvent((message) => {
1551→      if (
1552→        String((message as {sessionId?: string}).sessionId || '') !== sessionId
1553→      ) {
1554→        return
1555→      }
1556→      const method = String(message.method || '')
1557→      if (method === 'Runtime.executionContextCreated') {
1558→        const context = (message as {params?: {context?: any}}).params?.context
1559→        const contextId = context?.id
1560→        if (typeof contextId === 'number') {
1561→          contextsById.set(contextId, context)
1562→        }
1563→        return
1564→      }
1565→      if (method === 'Runtime.executionContextDestroyed') {
1566→        const params =
1567→          (message as {params?: {executionContextId?: number}}).params || {}
1568→        if (typeof params.executionContextId === 'number') {
1569→          contextsById.delete(params.executionContextId)
1570→        }
1571→        return
1572→      }
1573→
1574→      if (method === 'Runtime.executionContextsCleared') {
1575→        contextsById.clear()
1576→      }
1577→    })
1578→
1579→    this.sessionContextsUnsubscribe.set(sessionId, unsubscribe)
1580→
1581→    await this.cdp.sendCommand('Runtime.enable', {}, sessionId)
1582→
1583→    // Wait briefly for Chrome to emit the initial executionContextCreated
1584→    // events for any contexts that already existed when the session attached.
1585→    await new Promise((resolve) => setTimeout(resolve, 100))
1586→
1587→    return Array.from(contextsById.values())
1588→  }
1589→
1590→  private releaseSessionContexts(sessionId: string): void {
1591→    const unsubscribe = this.sessionContextsUnsubscribe.get(sessionId)
1592→
1593→    if (unsubscribe) {
1594→      try {
1595→        unsubscribe()
1596→      } catch {
1597→        // Ignore listener teardown errors.
1598→      }
1599→    }
1600→
1601→    this.sessionContextsUnsubscribe.delete(sessionId)
1602→    this.sessionContexts.delete(sessionId)
1603→  }
1604→}
