397→  private async getSelectorProbes(selectors: string[]): Promise<
398→    Array<{
399→      selector: string
400→      count: number
401→      samples: Array<{
402→        tag: string
403→        id?: string
404→        classes?: string
405→        role?: string
406→        ariaLabel?: string
407→        textLength?: number
408→        textSnippet?: string
409→      }>
410→    }>
411→  > {
412→    if (!this.cdpClient || !this.currentSessionId) return []
413→    if (!selectors.length) return []
414→    try {
415→      const payload = await this.cdpClient.evaluate(
416→        this.currentSessionId,
417→        `(() => {
418→          const selectors = ${JSON.stringify(selectors)};
419→          const limit = 3;
420→          const snippetLen = 140;
421→          return selectors.map((selector) => {
422→            let nodes = [];
423→            try {
424→              nodes = Array.from(document.querySelectorAll(selector));
425→            } catch (e) {
426→              return {selector, count: 0, samples: []};
427→            }
428→            const samples = nodes.slice(0, limit).map((node) => {
429→              const text = (node && node.textContent) ? String(node.textContent) : '';
430→              return {
431→                tag: node && node.tagName ? String(node.tagName).toLowerCase() : 'unknown',
432→                id: node && node.id ? String(node.id) : undefined,
433→                classes: node && node.className ? String(node.className) : undefined,
434→                role: node && node.getAttribute ? node.getAttribute('role') : undefined,
435→                ariaLabel: node && node.getAttribute ? node.getAttribute('aria-label') : undefined,
436→                textLength: text.length,
437→                textSnippet: text.trim().slice(0, snippetLen)
438→              };
439→            });
440→            return {selector, count: nodes.length, samples};
441→          });
442→        })()`
443→      )
444→      if (Array.isArray(payload)) return payload as any
445→    } catch {
446→      // ignore
447→    }
448→    return []
449→  }
