896→  // The main step for the user: open a URL and get its HTML content
897→  async inspectSource(
898→    url: string,
899→    options?: {
900→      forceNavigate?: boolean
901→    }
902→  ): Promise<string> {
903→    if (!this.cdpClient) {
904→      throw new Error(messages.sourceInspectorNotInitialized())
905→    }
906→
907→    try {
908→      if (this.isAuthorMode()) {
909→        console.log(messages.sourceInspectorOpeningUrl(url))
910→        console.log(messages.sourceInspectorFindingExistingTarget())
911→      }
912→
913→      emitActionEvent('navigation_start', {url})
914→      const {targetId, sessionId} = await ensureTargetAndSession(
915→        this.cdpClient,
916→        url,
917→        options
918→      )
919→      this.currentTargetId = targetId
920→      this.currentSessionId = sessionId
921→
922→      if (this.isAuthorMode()) {
923→        console.log(messages.sourceInspectorWaitingForPageLoad())
924→      }
925→
926→      await this.cdpClient.waitForLoadEvent(this.currentSessionId)
927→      emitActionEvent('navigation_end', {url})
928→
929→      // Fast initial extract for reliability under short auto-exit windows
930→      // Print immediately for --source users to see something quickly
931→      try {
932→        const outputConfig = this.getOutputConfig()
933→        const initialHtml = await extractPageHtml(
934→          this.cdpClient,
935→          this.currentSessionId,
936→          this.isAuthorMode(),
937→          outputConfig.includeShadow
938→        )
939→        await this.emitSourceOutput(String(initialHtml || ''), 'pre_injection')
940→      } catch {
941→        // best-effort initial print
942→      }
943→
944→      if (this.isAuthorMode()) {
945→        console.log(messages.sourceInspectorWaitingForContentScripts())
946→      }
947→
948→      const injected = await this.cdpClient.waitForContentScriptInjection(
949→        this.currentSessionId
950→      )
951→      const emitInjection = await this.shouldEmitContentScriptInjected(injected)
952→      if (emitInjection) {
953→        emitActionEvent('content_script_injected', {url})
954→      }
955→
956→      if (!injected) {
957→        await this.cdpClient.pollForVisibleShadowHostContent(
958→          this.currentSessionId
959→        )
960→      }
961→
962→      try {
963→        await this.waitForContentScriptStyles(this.currentSessionId)
964→      } catch {
