195→  private async getDomSnapshot(): Promise<DomSnapshot | undefined> {
196→    if (!this.cdpClient || !this.currentSessionId) return undefined
197→    const includeShadow = this.devOptions.sourceIncludeShadow !== 'off'
198→    try {
199→      const payload = await this.cdpClient.evaluate(
200→        this.currentSessionId,
201→        `(() => {
202→          const rootEl = document.querySelector('#extension-root,[data-extension-root]:not([data-extension-root="extension-js-devtools"])');
203→          if (!rootEl) return null;
204→          const root = (${includeShadow ? 'rootEl.shadowRoot || rootEl' : 'rootEl'});
205→          const maxDepth = 6;
206→          const maxNodes = 500;
207→          let count = 0;
208→          let truncated = false;
209→          const nodes = [];
210→          const childIndex = (node) => {
211→            if (!node || !node.parentElement) return 0;
212→            const siblings = Array.from(node.parentElement.children || []);
213→            return siblings.indexOf(node);
214→          };
215→          const walk = (node, depth, path) => {
216→            if (!node || depth > maxDepth || count >= maxNodes) {
217→              truncated = truncated || count >= maxNodes;
218→              return;
219→            }
220→            if (node.nodeType !== 1) return;
221→            count++;
222→            const el = node;
223→            const text = el.textContent ? String(el.textContent).trim() : '';
224→            const key = path;
225→            nodes.push({
226→              key,
227→              tag: el.tagName ? String(el.tagName).toLowerCase() : 'unknown',
228→              id: el.id ? String(el.id) : undefined,
229→              classes: el.className ? String(el.className) : undefined,
230→              role: el.getAttribute ? el.getAttribute('role') : undefined,
231→              ariaLabel: el.getAttribute ? el.getAttribute('aria-label') : undefined,
232→              name: el.getAttribute ? el.getAttribute('name') : undefined,
233→              type: el.getAttribute ? el.getAttribute('type') : undefined,
234→              textLength: text.length,
235→              childCount: el.children ? el.children.length : 0
236→            });
237→            if (depth >= maxDepth) return;
238→            const children = el.children ? Array.from(el.children) : [];
239→            for (const child of children) {
240→              const idx = childIndex(child);
241→              const childPath =
242→                path +
243→                '/' +
244→                child.tagName.toLowerCase() +
245→                '[' +
246→                idx +
247→                ']';
248→              walk(child, depth + 1, childPath);
249→            }
250→          };
251→          const rootKey = root === rootEl
252→            ? rootEl.tagName.toLowerCase() + '[0]'
253→            : rootEl.tagName.toLowerCase() + '[0]/shadow-root[0]';
254→          walk(root, 0, rootKey);
255→          return {
256→            rootMode: root === rootEl ? 'element' : 'shadow',
257→            depthLimit: maxDepth,
258→            nodeLimit: maxNodes,
259→            truncated,
260→            nodes
261→          };
262→        })()`
263→      )
264→      if (payload && typeof payload === 'object') return payload as DomSnapshot
265→    } catch {
266→      // ignore
267→    }
268→    return undefined
269→  }
