587→  private buildPrettyTitle(
588→    stage: SourceStage,
589→    url?: string,
590→    title?: string
591→  ): string {
592→    const parts: string[] = []
593→    if (stage === 'updated') {
594→      parts.push('UPDATED - after content script injection')
595→    } else if (stage === 'pre_injection') {
596→      parts.push('INITIAL - before content script injection')
597→    }
598→
599→    if (url || title) {
600→      const urlPart = url ? `URL: ${url}` : 'URL: unknown'
601→      const titlePart = title ? `TITLE: ${title}` : 'TITLE: unknown'
602→      parts.push(`${urlPart} | ${titlePart}`)
603→    }
604→
605→    if (parts.length === 0) return 'HTML'
606→
607→    return parts.join(' | ')
608→  }
