613→    const frameContext = await this.getFrameContext()
614→    const redacted = applySourceRedaction(html, outputConfig.redact)
615→    const summary = outputConfig.summary
616→      ? buildHtmlSummary(redacted)
617→      : undefined
618→    const {output, truncated, byteLength} = truncateByBytes(
619→      redacted,
620→      outputConfig.maxBytes
621→    )
622→    const hash = hashStringFNV1a(output)
623→    const shouldDiff =
624→      Boolean(this.devOptions.sourceDiff) && stage === 'updated'
625→    const diff =
626→      shouldDiff && this.lastOutputHash
627→        ? {
628→            changed: this.lastOutputHash !== hash,
629→            prevHash: this.lastOutputHash,
630→            hash,
631→            byteDelta:
632→              typeof this.lastByteLength === 'number'
633→                ? byteLength - this.lastByteLength
634→                : undefined,
635→            summaryDelta:
636→              summary && this.lastSummary
637→                ? {
638→                    extensionRoots:
639→                      summary.counts.extensionRoots -
640→                      this.lastSummary.counts.extensionRoots,
641→                    shadowRoots:
642→                      summary.counts.shadowRoots -
643→                      this.lastSummary.counts.shadowRoots,
644→                    scripts:
645→                      summary.counts.scripts - this.lastSummary.counts.scripts,
646→                    styles:
647→                      summary.counts.styles - this.lastSummary.counts.styles,
648→                    snippetChanged: summary.snippet !== this.lastSummary.snippet
649→                  }
650→                : undefined
651→          }
652→        : undefined
653→
654→    if (outputConfig.format === 'pretty') {
655→      console.log(messages.sourceInspectorHTMLOutputHeader())
656→      const heading = outputConfig.summary
657→        ? `SUMMARY - ${this.buildPrettyTitle(stage, url, title)}`
658→        : this.buildPrettyTitle(stage, url, title)
659→      console.log(messages.sourceInspectorHTMLOutputTitle(heading))
660→      console.log(
661→        formatHtmlSentinelBegin({
662→          url,
663→          title,
664→          stage,
665→          truncated
666→        })
667→      )
668→      console.log(
669→        outputConfig.summary ? JSON.stringify(summary, null, 2) : output
670→      )
671→
672→      if (diff && diff.changed) {
673→        console.log(
674→          messages.sourceInspectorHTMLOutputTitle(
675→            `DIFF - byteDelta=${diff.byteDelta ?? 'n/a'}`
676→          )
677→        )
678→      }
679→      console.log(formatHtmlSentinelEnd())
680→
681→      if (truncated && outputConfig.maxBytes > 0) {
682→        console.log(
683→          messages.sourceInspectorHTMLOutputTitle(
684→            `TRUNCATED - showing first ${outputConfig.maxBytes} bytes (set --source-max-bytes or EXTENSION_SOURCE_MAX_BYTES to adjust)`
685→          )
686→        )
687→      }
688→
689→      console.log(messages.sourceInspectorHTMLOutputFooter())
690→      this.lastOutputHash = hash
691→      this.lastByteLength = byteLength
692→      this.lastSummary = summary
693→
694→      emitActionEvent('source_snapshot_captured', {stage})
695→      await this.emitExtraOutputs(stage, {url, title, frameContext})
696→      return
697→    }
698→
699→    const eventBase = {
700→      schema_version: '1.0',
701→      timestamp: new Date().toISOString(),
702→      stage,
703→      browser: this.devOptions.browser,
704→      mode: this.runtimeMode,
705→      url,
706→      title,
707→      frameId: frameContext.frameId,
708→      frameUrl: frameContext.frameUrl,
709→      executionContextId: frameContext.executionContextId,
710→      tabId: undefined as number | string | undefined,
711→      truncated,
712→      byteLength,
713→      maxBytes: outputConfig.maxBytes,
714→      redaction: outputConfig.redact,
715→      includeShadow: outputConfig.includeShadow,
716→      source: 'extension.js'
717→    }
718→
719→    if (outputConfig.summary) {
720→      const payload = {
721→        type: 'page_html_summary',
722→        ...eventBase,
723→        summary,
724→        diff
725→      }
726→      console.log(JSON.stringify(payload))
727→      this.lastOutputHash = hash
728→      this.lastByteLength = byteLength
729→      this.lastSummary = summary
730→      emitActionEvent('source_snapshot_captured', {stage})
731→      await this.emitExtraOutputs(stage, {url, title, frameContext})
732→      return
733→    }
734→
735→    const payload = {
736→      type: 'page_html',
737→      ...eventBase,
738→      html: output,
739→      diff
740→    }
741→    console.log(JSON.stringify(payload))
742→    this.lastOutputHash = hash
743→    this.lastByteLength = byteLength
744→    this.lastSummary = summary
745→    emitActionEvent('source_snapshot_captured', {stage})
746→    await this.emitExtraOutputs(stage, {url, title, frameContext})
747→  }
748→
749→  private async emitExtraOutputs(
750→    stage: SourceStage,
751→    meta: {
752→      url?: string
753→      title?: string
754→      frameContext?: {
755→        frameId?: string
756→        frameUrl?: string
757→        executionContextId?: number
758→      }
759→    }
760→  ) {
761→    if (this.devOptions.sourceMeta) {
762→      const metaSnapshot = await this.getPageMetaSnapshot()
763→      this.emitEventPayload('page_meta', stage, meta, metaSnapshot)
764→      const rootMeta = await this.getExtensionRootMeta()
765→      if (rootMeta) {
766→        this.emitEventPayload('extension_root_meta', stage, meta, rootMeta)
767→      }
768→      const styleSnapshot = await this.getShadowStyleSnapshot()
769→      if (styleSnapshot) {
770→        this.emitEventPayload('shadow_style_output', stage, meta, styleSnapshot)
771→      }
772→    }
773→
774→    if (Array.isArray(this.devOptions.sourceProbe)) {
775→      const probes = await this.getSelectorProbes(this.devOptions.sourceProbe)
776→      this.emitEventPayload('selector_probe', stage, meta, {probes})
777→    }
778→
779→    if (this.devOptions.sourceTree && this.devOptions.sourceTree !== 'off') {
780→      const tree = await this.getExtensionRootTree()
781→
782→      if (tree) {
783→        this.emitEventPayload('extension_root_tree', stage, meta, tree)
784→      }
785→    }
786→
787→    if (this.devOptions.sourceDom) {
788→      const snapshot = await this.getDomSnapshot()
789→      if (snapshot) {
790→        this.emitEventPayload('dom_snapshot', stage, meta, snapshot)
791→
792→        if (stage === 'updated') {
793→          const diff = diffDomSnapshots(this.lastDomSnapshot, snapshot)
794→          this.emitEventPayload('dom_diff', stage, meta, diff)
795→        }
796→        this.lastDomSnapshot = snapshot
797→      }
798→    }
799→
800→    if (this.devOptions.sourceConsole) {
801→      const top = Array.from(this.consoleTop.values())
802→        .sort((a, b) => b.count - a.count)
803→        .slice(0, 5)
804→
805→      this.emitEventPayload('console_summary', stage, meta, {
806→        counts: this.consoleCounts,
807→        top,
808→        supported: true
809→      })
810→    }
811→  }
812→
813→  private emitEventPayload(
814→    type: string,
815→    stage: SourceStage,
816→    meta: {
817→      url?: string
818→      title?: string
819→      frameContext?: {
820→        frameId?: string
821→        frameUrl?: string
822→        executionContextId?: number
823→      }
824→    },
825→    payload: Record<string, unknown>
826→  ) {
827→    const outputConfig = this.getOutputConfig()
828→    const base = {
829→      type,
830→      schema_version: '1.0',
831→      timestamp: new Date().toISOString(),
832→      stage,
833→      browser: this.devOptions.browser,
834→      mode: this.runtimeMode,
835→      url: meta.url,
836→      title: meta.title,
837→      frameId: meta.frameContext?.frameId,
838→      frameUrl: meta.frameContext?.frameUrl,
839→      executionContextId: meta.frameContext?.executionContextId,
840→      source: 'extension.js'
841→    }
842→
843→    if (outputConfig.format === 'pretty') {
844→      console.log(messages.sourceInspectorHTMLOutputHeader())
845→      console.log(messages.sourceInspectorHTMLOutputTitle(type))
846→      console.log(JSON.stringify({...base, ...payload}, null, 2))
847→      console.log(messages.sourceInspectorHTMLOutputFooter())
848→      return
849→    }
850→
851→    console.log(JSON.stringify({...base, ...payload}))
852→  }
853→
854→  private async getShadowStyleSnapshot(): Promise<
855→    Record<string, unknown> | undefined
856→  > {
857→    if (!this.cdpClient || !this.currentSessionId) return undefined
858→    try {
859→      return await this.cdpClient.getShadowStyleSnapshot(this.currentSessionId)
860→    } catch {
861→      return undefined
862→    }
863→  }
864→
865→  private async getCdpPort(): Promise<number> {
866→    const instanceId = this.devOptions.instanceId
867→    return deriveDebugPortWithInstance(this.devOptions.port, instanceId)
868→  }
869→
870→  async initialize(port?: number): Promise<void> {
871→    try {
872→      if (!port) port = await this.getCdpPort()
873→
874→      const instanceId = this.devOptions.instanceId
875→      await waitForChromeRemoteDebugging(port, instanceId)
876→
877→      this.cdpClient = new CDPClient(port)
878→      await this.cdpClient.connect()
879→      this.setupConsoleCapture()
880→
881→      if (this.isAuthorMode()) {
882→        console.log(messages.sourceInspectorInitialized())
883→      }
884→
885→      this.isInitialized = true
886→    } catch (error) {
887→      if (this.isAuthorMode()) {
888→        console.error(
889→          messages.sourceInspectorInitializationFailed((error as Error).message)
890→        )
891→      }
892→      throw error
893→    }
894→  }
895→
896→  // The main step for the user: open a URL and get its HTML content
897→  async inspectSource(
898→    url: string,
899→    options?: {
900→      forceNavigate?: boolean
901→    }
902→  ): Promise<string> {
903→    if (!this.cdpClient) {
904→      throw new Error(messages.sourceInspectorNotInitialized())
905→    }
906→
907→    try {
908→      if (this.isAuthorMode()) {
909→        console.log(messages.sourceInspectorOpeningUrl(url))
910→        console.log(messages.sourceInspectorFindingExistingTarget())
911→      }
912→
913→      emitActionEvent('navigation_start', {url})
914→      const {targetId, sessionId} = await ensureTargetAndSession(
915→        this.cdpClient,
916→        url,
917→        options
918→      )
919→      this.currentTargetId = targetId
920→      this.currentSessionId = sessionId
921→
922→      if (this.isAuthorMode()) {
923→        console.log(messages.sourceInspectorWaitingForPageLoad())
924→      }
925→
926→      await this.cdpClient.waitForLoadEvent(this.currentSessionId)
927→      emitActionEvent('navigation_end', {url})
928→
929→      // Fast initial extract for reliability under short auto-exit windows
930→      // Print immediately for --source users to see something quickly
931→      try {
932→        const outputConfig = this.getOutputConfig()
933→        const initialHtml = await extractPageHtml(
934→          this.cdpClient,
935→          this.currentSessionId,
936→          this.isAuthorMode(),
937→          outputConfig.includeShadow
938→        )
939→        await this.emitSourceOutput(String(initialHtml || ''), 'pre_injection')
940→      } catch {
941→        // best-effort initial print
942→      }
943→
944→      if (this.isAuthorMode()) {
945→        console.log(messages.sourceInspectorWaitingForContentScripts())
946→      }
947→
948→      const injected = await this.cdpClient.waitForContentScriptInjection(
949→        this.currentSessionId
950→      )
951→      const emitInjection = await this.shouldEmitContentScriptInjected(injected)
952→      if (emitInjection) {
953→        emitActionEvent('content_script_injected', {url})
954→      }
955→
956→      if (!injected) {
957→        await this.cdpClient.pollForVisibleShadowHostContent(
958→          this.currentSessionId
959→        )
960→      }
961→
962→      try {
963→        await this.waitForContentScriptStyles(this.currentSessionId)
964→      } catch {
965→        // Ignore style wait failures; HTML extraction still proceeds.
966→      }
967→
968→      // This is the real inspection data step for the user (post-injection):
969→      const outputConfig = this.getOutputConfig()
970→      const html = await extractPageHtml(
971→        this.cdpClient,
972→        this.currentSessionId,
973→        this.isAuthorMode(),
974→        outputConfig.includeShadow
975→      )
976→
977→      return html
978→    } catch (error) {
979→      if (this.isAuthorMode()) {
980→        console.error(
981→          messages.sourceInspectorInspectionFailed((error as Error).message)
982→        )
983→      }
984→
985→      throw error
986→    }
987→  }
