335→  /**
336→   * Require structural evidence (counted roots or shadow style nodes) after the
337→   * injection wait, with a short settle loop for async shadow hydration. Falls back to
338→   * the same shadow-innerHTML probe as {@link waitForContentScriptInjection}.
339→   */
340→  private async shouldEmitContentScriptInjected(
341→    injectionWaitOk: boolean
342→  ): Promise<boolean> {
343→    if (!injectionWaitOk || !this.cdpClient || !this.currentSessionId) {
344→      return false
345→    }
346→    const sessionId = this.currentSessionId
347→    const deadline = Date.now() + 2800
348→    while (Date.now() < deadline) {
349→      const rootMeta = await this.cdpClient.getExtensionRootMeta(sessionId)
350→      const shadow = await this.cdpClient.getShadowStyleSnapshot(sessionId)
351→      const hasUserRoot = Boolean(rootMeta && rootMeta.rootCount >= 1)
352→      const hasShadowStyles =
353→        shadow && typeof shadow.count === 'number' && Number(shadow.count) > 0
354→      if (hasUserRoot || hasShadowStyles) {
355→        return true
356→      }
357→      await new Promise((r) => setTimeout(r, 200))
358→    }
359→    return this.cdpClient.hasVisibleShadowHostContent(sessionId)
360→  }
