451→  private async getExtensionRootTree(): Promise<
452→    | {
453→        rootMode: 'shadow' | 'element'
454→        depthLimit: number
455→        nodeLimit: number
456→        truncated: boolean
457→        tree: any
458→      }
459→    | undefined
460→  > {
461→    if (!this.cdpClient || !this.currentSessionId) return undefined
462→    const includeShadow = this.devOptions.sourceIncludeShadow !== 'off'
463→
464→    try {
465→      const payload = await this.cdpClient.evaluate(
466→        this.currentSessionId,
467→        `(() => {
468→          const rootEl = document.querySelector('#extension-root,[data-extension-root]:not([data-extension-root="extension-js-devtools"])');
469→          if (!rootEl) return null;
470→          const root = (${includeShadow ? 'rootEl.shadowRoot || rootEl' : 'rootEl'});
471→          const maxDepth = 4;
472→          const maxNodes = 200;
473→          let count = 0;
474→          let truncated = false;
475→          const nodeInfo = (node, depth) => {
476→            if (!node || depth > maxDepth || count >= maxNodes) {
477→              truncated = truncated || count >= maxNodes;
478→              return null;
479→            }
480→            if (node.nodeType !== 1) return null;
481→            count++;
482→            const el = node;
483→            const text = el.textContent ? String(el.textContent).trim() : '';
484→            const children = [];
485→            if (depth < maxDepth) {
486→              const nodes = el.children ? Array.from(el.children) : [];
487→              for (const child of nodes) {
488→                const childInfo = nodeInfo(child, depth + 1);
489→                if (childInfo) children.push(childInfo);
490→              }
491→            }
492→            return {
493→              tag: el.tagName ? String(el.tagName).toLowerCase() : 'unknown',
494→              id: el.id ? String(el.id) : undefined,
495→              classes: el.className ? String(el.className) : undefined,
496→              role: el.getAttribute ? el.getAttribute('role') : undefined,
497→              ariaLabel: el.getAttribute ? el.getAttribute('aria-label') : undefined,
498→              textLength: text.length,
499→              childCount: children.length,
500→              children
501→            };
502→          };
503→          const tree = nodeInfo(root, 0);
504→          return {
505→            rootMode: root === rootEl ? 'element' : 'shadow',
506→            depthLimit: maxDepth,
507→            nodeLimit: maxNodes,
508→            truncated,
509→            tree
510→          };
511→        })()`
512→      )
513→      if (payload && typeof payload === 'object') return payload as any
514→    } catch {
515→      // ignore
516→    }
517→    return undefined
518→  }
