520→  private setupConsoleCapture() {
521→    if (!this.cdpClient) return
522→
523→    const cdp = this.cdpClient as unknown as {
524→      onProtocolEvent?: (cb: (message: Record<string, unknown>) => void) => void
525→    }
526→
527→    if (typeof cdp.onProtocolEvent !== 'function') return
528→
529→    cdp.onProtocolEvent((message: Record<string, unknown>) => {
530→      const method = String(message.method || '')
531→      const params = (message as any).params || {}
532→
533→      if (method === 'Log.entryAdded') {
534→        const entry = params.entry || {}
535→        const level = String(entry.level || 'log')
536→        const text = String(entry.text || '')
537→        const sourceUrl = entry.url ? String(entry.url) : undefined
538→        this.recordConsoleEvent(level, text, sourceUrl)
539→      }
540→
541→      if (method === 'Runtime.consoleAPICalled') {
542→        const type = String(params.type || 'log')
543→        const args = Array.isArray(params.args) ? params.args : []
544→        const stack = params.stackTrace || {}
545→        const frame = Array.isArray(stack.callFrames)
546→          ? stack.callFrames[0]
547→          : null
548→        const sourceUrl = frame && frame.url ? String(frame.url) : undefined
549→        const text = args
550→          .map((arg: any) => {
551→            if (typeof arg?.value !== 'undefined') return String(arg.value)
552→            if (typeof arg?.description !== 'undefined')
553→              return String(arg.description)
554→            return ''
555→          })
556→          .filter(Boolean)
557→          .join(' ')
558→        this.recordConsoleEvent(type, text, sourceUrl)
559→      }
560→    })
561→  }
562→
563→  private recordConsoleEvent(level: string, text: string, sourceUrl?: string) {
564→    const normalized = ['error', 'warn', 'info', 'debug', 'log'].includes(level)
565→      ? level
566→      : 'log'
567→
568→    if (normalized in this.consoleCounts) {
569→      ;(this.consoleCounts as any)[normalized] += 1
570→    }
571→
572→    const hash = hashStringFNV1a(`${normalized}:${text}:${sourceUrl || ''}`)
573→    const existing = this.consoleTop.get(hash)
574→
575→    if (existing) {
576→      existing.count += 1
577→    } else {
578→      this.consoleTop.set(hash, {
579→        level: normalized,
580→        text,
581→        count: 1,
582→        sourceUrl
583→      })
584→    }
585→  }
