254→  const preferredContext = contexts.find((context) => {
255→    const auxData = context?.auxData || {}
256→    return (
257→      auxData.type === 'isolated' &&
258→      String(context?.origin || '').startsWith('chrome-extension://')
259→    )
260→  })
261→  if (typeof preferredContext?.id === 'number') {
262→    return preferredContext.id
263→  }
264→
265→  const fallbackContext = contexts.find(
266→    (context) => context?.auxData?.type === 'isolated'
267→  )
268→  return typeof fallbackContext?.id === 'number'
269→    ? fallbackContext.id
270→    : undefined
271→}
