273→export async function evaluateWithContentContext<T = unknown>(
274→  cdp: CDPClient,
275→  sessionId: string,
276→  expression: string,
277→  shouldAccept: (value: unknown) => boolean
278→): Promise<T | undefined> {
279→  let pageResult: unknown
280→  try {
281→    pageResult = await cdp.evaluate(sessionId, expression)
282→    if (shouldAccept(pageResult)) {
283→      return pageResult as T
284→    }
285→  } catch {
286→    // ignore and try the isolated content-script context next
287→  }
288→
289→  try {
290→    const isolatedContextId = await getIsolatedContextId(cdp, sessionId)
291→    if (typeof isolatedContextId === 'number') {
292→      const isolatedResult = await cdp.evaluateInContext(
293→        sessionId,
294→        expression,
295→        isolatedContextId
296→      )
297→      if (shouldAccept(isolatedResult)) {
298→        return isolatedResult as T
299→      }
300→      if (typeof pageResult !== 'undefined') {
301→        return pageResult as T
302→      }
303→      return isolatedResult as T
304→    }
305→  } catch {
306→    // ignore and fall back to the page result
307→  }
308→
309→  return pageResult as T | undefined
310→}
