365→/** Used after navigation when injection wait timed out — polls with isolated-world fallback. */
366→export async function pollForVisibleShadowHostContent(
367→  cdp: CDPClient,
368→  sessionId: string,
369→  deadlineMs = 4000
370→): Promise<void> {
371→  const deadline = Date.now() + deadlineMs
372→  const started = Date.now()
373→  while (Date.now() < deadline) {
374→    try {
375→      const hasRoot = await hasVisibleShadowHostContent(cdp, sessionId)
376→      if (hasRoot) return
377→    } catch {
378→      // ignore
379→    }
380→    const elapsed = Date.now() - started
381→    const delay = elapsed < 1000 ? 150 : 350
382→    await new Promise((r) => setTimeout(r, delay))
383→  }
