404→export async function getPageHTML(
405→  cdp: CDPClient,
406→  sessionId: string,
407→  includeShadow: 'off' | 'open-only' | 'all' = 'open-only'
408→): Promise<string> {
409→  try {
410→    const testResult = await cdp.evaluate(sessionId, 'document.title')
411→    if (typeof testResult !== 'string') {
412→      // Ignore, proceed. Some sites guard document.title access
413→    }
414→  } catch {
415→    // ignore
416→  }
417→
418→  const mainHTMLRaw = await cdp.evaluate(
419→    sessionId,
420→    `(() => {
421→        try {
422→          const serialize = () => {
423→            const doctype = document.doctype  
424→            const dt = doctype
425→              ? '<!DOCTYPE '
426→                + doctype.name
427→                + (doctype.publicId ? ' PUBLIC "' + doctype.publicId + '"' : '')
428→                + (doctype.systemId ? ' "' + doctype.systemId + '"' : '')
429→                + '>'
430→              : ''
431→            return dt + '\n' + document.documentElement.outerHTML
432→          }
433→          return serialize()
434→        } catch (e) {
435→          return ''
436→        }
437→      })()`
438→  )
439→  const mainHTML =
440→    typeof mainHTMLRaw === 'string' ? mainHTMLRaw : String(mainHTMLRaw || '')
441→
442→  if (includeShadow === 'off') {
443→    return mainHTML
444→  }
445→
446→  const hasVisibleContentRoot = await evaluateWithContentContext<boolean>(
447→    cdp,
448→    sessionId,
449→    `(() => {
450→      try {
451→        return !!document.querySelector(${JSON.stringify(
452→          CONTENT_ROOT_SELECTOR
453→        )})
454→      } catch {
455→        return false
456→      }
457→    })()`,
458→    (value) => typeof value === 'boolean'
459→  )
460→
461→  if (!hasVisibleContentRoot) {
462→    return mainHTML
463→  }
464→
465→  // Attempt full page-context serialization with shadow content injected into a cloned document.
466→  // This avoids relying on sr.innerHTML visibility nuances.
467→  try {
