480→            var cloneDoc = cloned.ownerDocument || document;
481→            var cloneBody = cloned.querySelector('body') || cloned;
482→            for (var missingIndex = clonedHosts.length; missingIndex < liveHosts.length; missingIndex++) {
483→              var missingLiveHost = liveHosts[missingIndex];
484→              if (!missingLiveHost || !missingLiveHost.tagName || !cloneBody || typeof cloneBody.appendChild !== 'function') continue;
