582→export async function waitForLoadEvent(
583→  cdp: CDPClient,
584→  sessionId: string
585→): Promise<void> {
586→  return new Promise((resolve) => {
587→    let resolved = false
588→
589→    const listener = (data: string) => {
590→      try {
591→        const message = JSON.parse(data) as {
592→          method?: string
593→          sessionId?: string
594→        }
595→        if (
596→          message.method === 'Page.loadEventFired' &&
597→          message.sessionId === sessionId &&
598→          !resolved
599→        ) {
600→          resolved = true
601→          resolve()
602→        }
603→      } catch {
604→        // ignore
605→      }
606→    }
607→
608→    const clientWithHandle = cdp as unknown as {
609→      handleMessage: (data: string) => void
610→    }
611→    const original = clientWithHandle.handleMessage.bind(cdp)
612→
613→    clientWithHandle.handleMessage = (data: string) => {
614→      original(data)
615→      listener(data)
616→    }
617→
618→    setTimeout(() => {
619→      if (!resolved) {
620→        resolved = true
621→        console.log(messages.cdpClientLoadEventTimeout())
622→        resolve()
623→      }
624→
625→      clientWithHandle.handleMessage = original
626→    }, 2000)
627→  })
628→}
