643→          const hosts = Array.from(document.querySelectorAll(${JSON.stringify(
644→            CONTENT_ROOT_SELECTOR
645→          )}));
646→          if (!hosts.length) return false;
647→          const markers = ['iskilar_box','content_script','content_title','js-probe'];
648→          for (const h of hosts) {
649→            try {
650→              const sr = h && h.shadowRoot;
651→              if (!sr) continue;
652→              const html = String(sr.innerHTML||'');
653→              if (html.length > 0) return true;
654→              if (markers.some((m) => html.includes(m))) return true;
655→              try {
656→                const parts = Array.from(sr.children).map((n) => (n && n.outerHTML) ? String(n.outerHTML) : '').join('');
657→                if (parts && parts.length) return true;
658→                if (markers.some((m) => parts.includes(m))) return true;
659→              } catch { /* ignore */ }
660→            } catch { /* ignore */ }
661→          }
662→          return false;
663→        } catch { return false } })()`,
664→        (value) => Boolean(value)
665→      )
666→
667→      if (Boolean(injected)) return true
668→    } catch {
669→      // ignore
670→    }
671→
672→    const elapsed = Date.now() - started
673→    const delay = elapsed < 2000 ? 150 : 500
674→
675→    await new Promise((r) => setTimeout(r, delay))
676→  }
677→
678→  return false
679→}
