16→/** Serialized snapshot of extension content roots / reinject markers (same shape as ChromiumSourceInspectionPlugin root meta). */
17→export type ExtensionRootMetaPayload = {
18→  rootCount: number
19→  markerCount: number
20→  latestGeneration: number
21→  roots: Array<{
22→    tag: string
23→    id?: string
24→    key?: string
25→    generation?: number
26→    status?: string
27→    build?: string
28→  }>
29→  markers: Array<{
30→    tag: string
31→    id?: string
32→    key?: string
33→    generation?: number
34→    status?: string
35→    build?: string
36→  }>
37→  registries: Array<{
38→    key: string
39→    generation?: number
40→    hasCleanup?: boolean
41→    build?: string
42→  }>
43→  page?: {
44→    key?: string
45→    generation?: number
46→    status?: string
47→    build?: string
48→  }
49→}
