51→const EXTENSION_ROOT_META_EXPRESSION = `(() => {
52→          const readGeneration = (node) => {
53→            try {
54→              const raw = node && node.getAttribute
55→                ? node.getAttribute('data-extjs-reinject-generation')
56→                : '';
57→              const parsed = Number(raw);
58→              return Number.isFinite(parsed) ? parsed : undefined;
59→            } catch (error) {
60→              return undefined;
61→            }
62→          };
63→          const normalize = (node) => ({
64→            tag: node && node.tagName ? String(node.tagName).toLowerCase() : 'unknown',
65→            id: node && node.id ? String(node.id) : undefined,
66→            key: node && node.getAttribute ? node.getAttribute('data-extjs-reinject-key') || undefined : undefined,
67→            generation: readGeneration(node),
68→            status: node && node.getAttribute ? node.getAttribute('data-extjs-reinject-status') || undefined : undefined,
69→            build: node && node.getAttribute ? node.getAttribute('data-extjs-reinject-build') || undefined : undefined,
70→            hasShadowRoot: !!(node && node.shadowRoot),
71→            hasShadowContent: !!(node && node.shadowRoot && String(node.shadowRoot.innerHTML || '').trim())
72→          });
73→          const registry = (typeof globalThis === 'object' && globalThis)
74→            ? (globalThis.__EXTENSIONJS_DEV_REINJECT__ || {})
75→            : {};
76→          const registries = Object.entries(registry)
77→            .slice(0, 10)
78→            .map(([key, entry]) => {
79→              const candidate = entry && typeof entry === 'object' ? entry : {};
80→              const cleanup = candidate && typeof candidate.cleanup === 'function'
81→                ? candidate.cleanup
82→                : (typeof entry === 'function' ? entry : undefined);
83→              return {
84→                key,
85→                generation: typeof candidate.generation === 'number'
86→                  ? candidate.generation
87→                  : (cleanup && typeof cleanup.__extjsGeneration === 'number'
88→                    ? cleanup.__extjsGeneration
89→                    : undefined),
90→                hasCleanup: typeof cleanup === 'function',
91→                build: typeof candidate.build === 'string'
92→                  ? candidate.build
93→                  : (cleanup && typeof cleanup.__extjsBuild === 'string'
94→                    ? cleanup.__extjsBuild
95→                    : undefined)
96→              };
97→            });
98→          const pageCandidate = {
99→            key: document.documentElement.getAttribute('data-extjs-last-reinject-key') || undefined,
100→            generation: (() => {
101→              const parsed = Number(document.documentElement.getAttribute('data-extjs-last-reinject-generation') || '');
102→              return Number.isFinite(parsed) ? parsed : undefined;
103→            })(),
104→            status: document.documentElement.getAttribute('data-extjs-last-reinject-status') || undefined,
105→            build: document.documentElement.getAttribute('data-extjs-last-reinject-build') || undefined
106→          };
107→          const roots = Array.from(
108→            document.querySelectorAll('#extension-root,[data-extension-root]:not([data-extension-root="extension-js-devtools"])')
109→          )
110→            .slice(0, 10)
111→            .map(normalize)
112→            .filter((entry) =>
113→              entry.hasShadowRoot ||
114→              entry.hasShadowContent ||
115→              typeof entry.key === 'string' ||
116→              typeof entry.generation === 'number' ||
117→              typeof entry.status === 'string' ||
118→              typeof entry.build === 'string'
119→            )
120→            .map(({hasShadowRoot, hasShadowContent, ...entry}) => entry);
121→          const markers = Array.from(
122→            document.querySelectorAll('[data-extjs-reinject-marker="true"]')
123→          )
124→            .slice(0, 10)
125→            .map(normalize);
126→          const pageHasBackingEvidence =
127→            roots.length > 0 ||
128→            markers.length > 0 ||
129→            registries.some((entry) =>
130→              entry.key === pageCandidate.key ||
131→              typeof entry.generation === 'number' ||
132→              !!entry.hasCleanup ||
133→              typeof entry.build === 'string'
134→            );
135→          const page = pageHasBackingEvidence ? pageCandidate : undefined;
136→          const generations = roots
137→            .concat(markers)
138→            .map((entry) => entry.generation)
139→            .concat(page && typeof page.generation === 'number' ? [page.generation] : [])
140→            .concat(
141→              registries
142→                .map((entry) => entry.generation)
143→                .filter((value) => typeof value === 'number')
144→            )
145→            .filter((value) => typeof value === 'number');
146→          return {
147→            rootCount: roots.length,
148→            markerCount: markers.length,
149→            latestGeneration: generations.length ? Math.max(...generations) : 0,
150→            roots,
151→            markers,
152→            registries,
153→            page
154→          };
155→        })()`
