312→function isExtensionRootMetaPayload(
313→  value: unknown
314→): value is ExtensionRootMetaPayload {
315→  if (!value || typeof value !== 'object') return false
316→  const v = value as ExtensionRootMetaPayload
317→  return (
318→    typeof v.rootCount === 'number' &&
319→    typeof v.markerCount === 'number' &&
320→    typeof v.latestGeneration === 'number' &&
321→    Array.isArray(v.roots) &&
322→    Array.isArray(v.markers) &&
323→    Array.isArray(v.registries)
324→  )
325→}
