202→    sendCommand?: (
203→      method: string,
204→      params?: Record<string, unknown>,
205→      sessionId?: string,
206→      timeoutMs?: number
207→    ) => Promise<unknown>
208→    onProtocolEvent?: (
209→      handler: (message: Record<string, unknown>) => void
210→    ) => () => void
211→  }
212→
213→  if (
214→    typeof rawCdp.sendCommand !== 'function' ||
215→    typeof rawCdp.onProtocolEvent !== 'function'
216→  ) {
217→    return []
218→  }
219→
220→  const contextsById = new Map<number, any>()
221→  const unsubscribe = rawCdp.onProtocolEvent((message) => {
222→    if (
223→      String((message as {sessionId?: string}).sessionId || '') !== sessionId
224→    ) {
225→      return
226→    }
227→    if (String(message.method || '') !== 'Runtime.executionContextCreated') {
228→      return
229→    }
230→    const context = (message as {params?: {context?: any}}).params?.context
231→    const contextId = context?.id
232→    if (typeof contextId === 'number') {
233→      contextsById.set(contextId, context)
234→    }
235→  })
236→
237→  try {
238→    await rawCdp.sendCommand('Runtime.enable', {}, sessionId, 3000)
239→    await new Promise((resolve) => setTimeout(resolve, 100))
240→  } catch {
241→    return []
242→  } finally {
243→    unsubscribe()
244→  }
245→
246→  return Array.from(contextsById.values())
247→}
