58→async function maybePrintDevBanner(args: {
59→  compilation: CompilationLike
60→  chromiumConfig: string[]
61→  browser: ChromiumLaunchOptions['browser']
62→  hostPort: {host: string; port: number}
63→  browserVersionLine?: string
64→  enableCdp: boolean
65→}) {
66→  const mode = (args.compilation?.options?.mode || 'development') as string
67→  if (mode !== 'development') return
68→  const loadExtensionFlag = args.chromiumConfig.find((flag: string) =>
69→    flag.startsWith('--load-extension=')
70→  )
71→  const extensionOutputPath = getExtensionOutputPath(
72→    args.compilation,
73→    loadExtensionFlag
74→  )
75→  if (!extensionOutputPath) return
76→  const ready = await waitForStableManifest(extensionOutputPath, {
77→    timeoutMs: 10000
78→  })
79→  if (!ready) return
80→  if (args.enableCdp) return
81→  await printDevBannerOnce({
82→    browser: args.browser,
83→    outPath: extensionOutputPath,
84→    hostPort: args.hostPort,
85→    getInfo: async () => null,
86→    browserVersionLine: args.browserVersionLine
87→  })
88→}
