90→/**
91→ * ChromiumLaunchPlugin
92→ *
93→ * Intended responsibilities (will be wired incrementally without changing inner logic):
94→ * - Resolve binary; compose flags (profiles, excludes, overrides)
95→ * - Allocate CDP port; spawn process; setup signals; dry-run
96→ * - Connect CDP; ensure extension loaded; print dev banner
97→ * - Publish controller + port via ChromiumContext
98→ */
99→export class ChromiumLaunchPlugin {
100→  private didLaunch = false
101→  private didReportReady = false
102→  private logger!: BrowserLogger
103→
104→  constructor(
105→    private readonly options: ChromiumLaunchOptions,
106→    private readonly ctx: ChromiumContext
107→  ) {}
108→
109→  /**
110→   * Run the Chromium launch flow without requiring a bundler compiler instance.
111→   * Intended for run-only preview paths.
112→   */
113→  public async runOnce(
114→    compilation: CompilationLike,
115→    opts?: {enableCdpPostLaunch?: boolean}
116→  ): Promise<void> {
117→    // Ensure we have a logger even without a compiler.
118→    if (!this.logger) {
119→      this.logger = {
120→        info: (...a: unknown[]) => console.log(...a),
121→        warn: (...a: unknown[]) => console.warn(...a),
122→        error: (...a: unknown[]) => console.error(...a),
123→        debug: (...a: unknown[]) => (console as any)?.debug?.(...a)
124→      } as BrowserLogger
125→    }
126→    await this.launchChromium(compilation, opts)
127→  }
128→
129→  apply(compiler: any) {
130→    this.logger =
131→      typeof compiler?.getInfrastructureLogger === 'function'
132→        ? compiler.getInfrastructureLogger('ChromiumLaunchPlugin')
133→        : ({
134→            info: (...a: unknown[]) => console.log(...a),
135→            warn: (...a: unknown[]) => console.warn(...a),
136→            error: (...a: unknown[]) => console.error(...a),
137→            debug: (...a: unknown[]) => (console as any)?.debug?.(...a)
138→          } as BrowserLogger)
139→
140→    compiler.hooks.done.tapPromise('chromium:launch', async (stats: any) => {
141→      try {
142→        const hasErrors =
143→          typeof stats?.hasErrors === 'function'
144→            ? stats.hasErrors()
145→            : !!stats?.compilation?.errors?.length
146→
147→        if (hasErrors) {
148→          this.logger.info(messages.skippingBrowserLaunchDueToCompileErrors())
149→          return
150→        }
151→
152→        if (this.didLaunch) {
153→          return
154→        }
155→
156→        await this.launchChromium(stats.compilation)
157→        this.didLaunch = true
158→        if (!this.didReportReady) {
159→          // Use console.log so the message is always visible; infrastructureLogging
160→          // level is 'error' by default, which would suppress logger.info()
161→          console.log(
162→            devServerReady(
163→              stats.compilation.options.mode as 'development' | 'production',
164→              this.options.browser
165→            )
166→          )
167→        }
168→      } catch (error) {
169→        // Do not swallow: otherwise users can get stuck at "compiled successfully"
170→        // with no feedback when the browser fails to launch (common in WSL/CI).
171→        try {
172→          this.logger.error(
173→            messages.browserLaunchError(this.options.browser as any, error)
174→          )
175→        } catch {
176→          // ignore
177→        }
178→      }
179→    })
180→  }
181→
182→  private async launchChromium(
183→    compilation: CompilationLike,
184→    opts?: {enableCdpPostLaunch?: boolean}
185→  ) {
186→    // Dry-run short-circuit
187→    if (
188→      this.options?.dryRun ||
189→      process.env.VITEST ||
190→      process.env.VITEST_WORKER_ID
191→    ) {
192→      logChromiumDryRun('chromium-mock-binary', [])
193→      return
194→    }
195→
196→    const browser: string = this.options?.browser
197→
198→    // Resolve binary (prefer output-resolved, then location helpers)
199→    let browserBinaryLocation: string | null = null
200→    let printedGuidance = false
201→    const normalizePath = (p: string | null): string | null => {
202→      if (!p) return null
203→      const normalized = normalizeBinaryPathForWsl(p)
204→      return normalized || null
205→    }
206→    const isUsableBinary = (p: string | null): p is string =>
207→      Boolean(p && fs.existsSync(p))
208→    const resolveManagedBinary = (): string | null => {
209→      try {
210→        const resolved = binariesResolver.resolveFromBinaries(
211→          compilation,
212→          browser === 'chromium' || browser === 'chromium-based'
213→            ? 'chromium'
214→            : browser === 'edge'
215→              ? 'edge'
216→              : 'chrome'
217→        )
218→        const normalized = normalizePath(resolved || null)
219→        return isUsableBinary(normalized) ? normalized : null
220→      } catch {
221→        return null
222→      }
223→    }
224→    const resolveWslFallback = (): string | null =>
225→      resolveWslWindowsBinary(browser)
226→    const getInstallGuidanceText = (
227→      target: 'chrome' | 'chromium' | 'edge'
228→    ): string => {
229→      try {
230→        if (target === 'edge') {
231→          return getEdgeInstallGuidance()
232→        }
233→        if (target === 'chromium') {
234→          return getChromiumInstallGuidance()
235→        }
236→        return getChromeInstallGuidance()
237→      } catch {
238→        return `npx extension install ${target}`
239→      }
240→    }
241→    const printInstallGuidance = (
242→      raw: string,
243→      browserName: ChromiumLaunchOptions['browser'] | 'edge' | 'chromium'
244→    ) => {
245→      this.printEnhancedPuppeteerInstallHint(compilation, raw, browserName)
246→      printedGuidance = true
247→    }
248→
249→    browserBinaryLocation = resolveManagedBinary()
250→
251→    let skipDetection = Boolean(browserBinaryLocation)
252→    if (!browserBinaryLocation && isWslEnv()) {
253→      // WSL+GUI: prefer a Linux-native browser so the dev loop stays
254→      // entirely on the Linux side (CDP, watchers, FDs all behave
255→      // normally). Fall back to the Windows binary via /mnt/c when no
256→      // Linux browser is installed or no GUI is available.
257→      const linuxFallback = resolveWslLinuxBinary(browser)
258→
259→      if (linuxFallback) {
260→        browserBinaryLocation = linuxFallback
261→        skipDetection = true
262→      } else {
263→        const wslFallback = resolveWslFallback()
264→
265→        if (wslFallback) {
266→          browserBinaryLocation = wslFallback
267→          skipDetection = true
268→        }
269→      }
270→    }
271→    // Swap any Chrome wrapper script for the real binary under WSL+GUI
272→    // — the wrapper closes extra FDs on exec, breaking CDP pipe.
273→    browserBinaryLocation = preferRealChromeBinary(browserBinaryLocation)
274→
275→    const getBrowserVersionLine = (bin: string): string => {
276→      try {
277→        if (browser === 'edge') {
278→          return getEdgeVersion(bin) || ''
279→        }
280→        if (browser === 'chromium' || browser === 'chromium-based') {
281→          return getChromiumVersion(bin) || ''
282→        }
283→        return getChromeVersion(bin) || ''
284→      } catch {
285→        return ''
286→      }
287→    }
288→
289→    const looksOfficialChromeBinaryPath = (bin: string): boolean => {
290→      const p = String(bin || '')
291→      if (!p) return false
292→      // macOS system Chrome install
293→      if (
294→        /\/Applications\/Google Chrome(?: (?:Beta|Dev|Canary))?\.app\/Contents\/MacOS\/Google Chrome/i.test(
295→          p
296→        )
297→      ) {
298→        return true
299→      }
300→      // Windows system Chrome install
301→      if (/\\Google\\Chrome\\Application\\chrome\.exe$/i.test(p)) return true
302→      // Linux system Chrome install (typical)
303→      if (/\/opt\/google\/chrome\//i.test(p)) return true
304→      if (/\/google-chrome(?:-stable)?$/i.test(p)) return true
305→      return false
306→    }
307→
308→    const managedCacheRoot =
309→      binariesResolver.computeBinariesBaseDir(compilation)
310→    const managedEnvFor = (b: ChromiumLaunchOptions['browser']) => ({
311→      ...process.env,
312→      ...binariesResolver.managedBrowserCacheEnv(String(managedCacheRoot), b)
313→    })
314→
315→    const isAuthorMode = process.env.EXTENSION_AUTHOR_MODE === 'true'
316→    const resolveChromeLikeBinary = (): string | null => {
317→      try {
318→        try {
319→          const env = managedEnvFor('chrome')
320→          const located = locateChrome(true, {env}) || null
321→          if (!located) throw new Error(getInstallGuidanceText('chrome'))
322→          const normalized = normalizePath(located || null)
323→          if (isUsableBinary(normalized)) {
324→            if (looksOfficialChromeBinaryPath(normalized) && !isWslEnv()) {
325→              printInstallGuidance(
326→                getInstallGuidanceText('chrome'),
327→                browser as any
328→              )
329→              return null
330→            }
331→            return normalized
332→          }
333→          return null
334→        } catch (err) {
335→          const env = managedEnvFor('chrome')
336→          let candidate: string | null = locateChrome(true, {env}) || null
337→          const normalized = normalizePath(candidate || null)
338→          if (normalized) {
339→            if (looksOfficialChromeBinaryPath(normalized) && !isWslEnv()) {
340→              printInstallGuidance(
341→                getInstallGuidanceText('chrome'),
342→                browser as any
343→              )
344→              candidate = null
345→            }
346→          }
347→          const resolved = normalizePath(candidate || null)
348→          const fallback = resolved || resolveWslFallback()
349→          if (!fallback) throw err
350→          return fallback
351→        }
352→      } catch (error) {
353→        printInstallGuidance(String(error), browser as any)
354→        return null
355→      }
356→    }
357→
358→    switch (browser) {
359→      case 'chrome': {
360→        if (isAuthorMode) console.log(messages.locatingBrowser(browser))
361→
362→        if (!skipDetection) {
363→          browserBinaryLocation = resolveChromeLikeBinary()
364→        }
365→        break
366→      }
367→
368→      case 'chromium': {
369→        if (isAuthorMode) console.log(messages.locatingBrowser(browser))
370→
371→        // Prefer explicit binary when provided
372→        browserBinaryLocation = this.options?.chromiumBinary || null
373→        // If user provided a binary, require it to exist
374→        if (this.options?.chromiumBinary) {
375→          const normalized = normalizePath(String(this.options.chromiumBinary))
376→          if (!normalized || !fs.existsSync(normalized)) {
377→            console.error(
378→              messages.invalidChromiumBinaryPath(
379→                String(this.options.chromiumBinary)
380→              )
381→            )
382→            process.exit(1)
383→          }
384→          browserBinaryLocation = normalized
385→        }
386→
387→        if (!browserBinaryLocation && !skipDetection) {
388→          try {
389→            const env = managedEnvFor('chromium')
390→            const p = locateChromium({env})
391→            const normalized = normalizePath(p || null)
392→            if (normalized && typeof normalized === 'string') {
393→              if (fs.existsSync(normalized)) browserBinaryLocation = normalized
394→            }
395→          } catch {
396→            // ignore; not fatal here
397→          }
398→        }
399→        if (!browserBinaryLocation) {
400→          browserBinaryLocation = resolveWslFallback()
401→        }
402→        break
403→      }
404→
405→      case 'edge': {
406→        if (isAuthorMode) console.log(messages.locatingBrowser(browser))
407→
408→        try {
409→          // Honor explicit env override first
410→          const override = String(process.env.EDGE_BINARY || '').trim()
411→          if (override) {
412→            const normalized = normalizePath(override)
413→            if (normalized && fs.existsSync(normalized)) {
414→              browserBinaryLocation = normalized
415→            } else {
416→              throw new Error('EDGE_BINARY points to a non-existent path')
417→            }
418→          } else {
419→            const env = managedEnvFor('edge')
420→            const located = locateEdge({env})
421→            const normalized = normalizePath(located || null)
422→            browserBinaryLocation = normalized
423→            // Validate detected path. If not found, show install guidance just like the catch block.
424→            if (
425→              !browserBinaryLocation ||
426→              !fs.existsSync(String(browserBinaryLocation))
427→            ) {
428→              const fallback = resolveWslWindowsBinary(browser)
429→              if (fallback) {
430→                browserBinaryLocation = fallback
431→                break
432→              }
433→              const guidance = getInstallGuidanceText('edge')
434→
435→              printInstallGuidance(guidance, 'edge')
436→              browserBinaryLocation = null
437→
438→              if (process.env.VITEST || process.env.VITEST_WORKER_ID) {
439→                throw new Error('Chromium launch failed')
440→              } else {
441→                process.exit(1)
442→              }
443→            }
444→          }
445→        } catch {
446→          const guidance = getInstallGuidanceText('edge')
447→
448→          const fallback = resolveWslFallback()
449→          if (fallback) {
450→            browserBinaryLocation = fallback
451→          } else {
452→            printInstallGuidance(guidance, 'edge')
453→            browserBinaryLocation = null
454→          }
455→
456→          if (!browserBinaryLocation) {
457→            if (process.env.VITEST || process.env.VITEST_WORKER_ID) {
458→              throw new Error('Chromium launch failed')
459→            } else {
460→              process.exit(1)
461→            }
462→          }
463→        }
464→        break
465→      }
466→
467→      case 'chromium-based': {
468→        // Prefer explicit binary; otherwise try chromium-location
469→        browserBinaryLocation = this.options?.chromiumBinary || null
470→        // Engine-based requires explicit working binary path
471→        if (this.options?.chromiumBinary) {
472→          const normalized = normalizePath(String(this.options.chromiumBinary))
473→          if (!normalized || !fs.existsSync(normalized)) {
474→            console.error(
475→              messages.invalidChromiumBinaryPath(
476→                String(this.options.chromiumBinary)
477→              )
478→            )
479→            process.exit(1)
480→          }
481→          browserBinaryLocation = normalized
482→        } else {
483→          console.error(messages.requireChromiumBinaryForChromiumBased())
484→          process.exit(1)
485→        }
486→        if (!browserBinaryLocation && !skipDetection) {
487→          try {
488→            const env = managedEnvFor('chromium')
489→            const p = locateChromium({env})
490→            const normalized = normalizePath(p || null)
491→            if (normalized && typeof normalized === 'string') {
492→              if (fs.existsSync(normalized)) browserBinaryLocation = normalized
493→            }
494→          } catch {
495→            // ignore
496→          }
497→        }
498→        if (!browserBinaryLocation) {
499→          browserBinaryLocation = resolveWslFallback()
500→        }
501→        break
502→      }
503→
504→      default: {
505→        browserBinaryLocation = resolveChromeLikeBinary()
506→        break
507→      }
508→    }
509→
510→    if (!browserBinaryLocation || !fs.existsSync(browserBinaryLocation)) {
511→      browserBinaryLocation = browserBinaryLocation || resolveManagedBinary()
512→
513→      if (!browserBinaryLocation) {
514→        browserBinaryLocation = resolveWslFallback()
515→      }
516→
517→      if (!browserBinaryLocation || !fs.existsSync(browserBinaryLocation)) {
518→        // Always print pretty guidance for Chromium flavors
519→        if (browser === 'chromium' || browser === 'chromium-based') {
520→          printInstallGuidance(getInstallGuidanceText('chromium'), 'chromium')
521→        }
522→
523→        if (
524→          !printedGuidance &&
525→          browser !== 'chromium' &&
526→          browser !== 'chromium-based'
527→        ) {
528→          this.logger.error(
529→            messages.browserNotInstalledError(
530→              browser as any,
531→              browserBinaryLocation || ''
532→            )
533→          )
534→        }
535→
536→        if (process.env.VITEST || process.env.VITEST_WORKER_ID) {
537→          throw new Error('Browser not installed or binary path not found')
538→        } else {
539→          process.exit(1)
540→        }
541→      }
542→    }
543→
544→    const extensionsToLoad = toExtensionLoadList(this.options.extension)
545→    publishUserExtensionRoot(extensionsToLoad, this.ctx.setExtensionRoot)
546→
547→    let chromiumConfig: string[] = browserConfig(compilation, {
548→      ...this.options,
549→      profile: this.options.profile,
550→      instanceId: this.options.instanceId,
551→      extension: extensionsToLoad,
552→      logLevel: this.options.logLevel
553→    })
554→
555→    const desiredPort = utils.deriveDebugPortWithInstance(
556→      this.options.port,
557→      this.options.instanceId
558→    )
559→    const freePort = await utils.findAvailablePortNear(desiredPort)
560→
561→    const selectedPort = freePort
562→
563→    if (freePort !== desiredPort) {
564→      chromiumConfig = chromiumConfig.map((flag) =>
565→        flag.startsWith('--remote-debugging-port=')
566→          ? `--remote-debugging-port=${selectedPort}`
567→          : flag
568→      )
569→    }
570→    if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
571→      this.logger.info(messages.devChromiumDebugPort(selectedPort, desiredPort))
572→    }
573→    instanceRegistry.setInstancePorts(this.options.instanceId, {
574→      cdpPort: selectedPort
575→    })
576→
577→    const enableCdp = opts?.enableCdpPostLaunch === false ? false : true
578→    await maybePrintDevBanner({
579→      compilation,
580→      chromiumConfig,
581→      browser: this.options.browser,
582→      hostPort: {host: '127.0.0.1', port: selectedPort},
583→      enableCdp
584→    })
585→
586→    if (this.options.dryRun) {
587→      logChromiumDryRun(browserBinaryLocation, chromiumConfig)
588→      return
589→    }
590→
591→    const usePipe = chromiumConfig.includes('--remote-debugging-pipe')
592→    const child = await this.launchWithDirectSpawn(
593→      browserBinaryLocation,
594→      chromiumConfig,
595→      usePipe
596→    )
597→
598→    // Extract pipe streams for CDP transport (fds 3 & 4 from Chrome)
599→    // child.stdio[3] = Writable (we write commands to Chrome)
600→    // child.stdio[4] = Readable (Chrome writes responses to us)
601→    const pipeStreams =
602→      usePipe && child?.stdio?.[3] && child?.stdio?.[4]
603→        ? {
604→            input: child.stdio[4] as import('stream').Readable,
605→            output: child.stdio[3] as import('stream').Writable
606→          }
607→        : undefined
608→
609→    // Verify the debug port is actually bound before proceeding (skip if using pipes)
610→    if (enableCdp && !pipeStreams) {
611→      let portReady = false
612→      for (let attempt = 0; attempt < 10; attempt++) {
613→        portReady = await checkChromeRemoteDebugging(selectedPort)
614→        if (portReady) break
615→        await new Promise((r) => setTimeout(r, 500))
616→      }
617→      if (!portReady && process.env.EXTENSION_AUTHOR_MODE === 'true') {
618→        this.logger.warn?.(
619→          `[browser] Debug port ${selectedPort} not bound after spawn — CDP may fail`
620→        )
621→      }
622→    }
623→
624→    if (compilation.options.mode === 'development' && !this.didReportReady) {
625→      // Use console.log so the message is always visible; infrastructureLogging
626→      // level is 'error' by default, which would suppress logger.info()
627→      console.log(
628→        devServerReady(
629→          compilation.options.mode as 'development' | 'production',
630→          this.options.browser
631→        )
632→      )
633→      this.didReportReady = true
634→    }
635→
636→    try {
637→      // Best-effort: derive a human-readable browser version line for dev/prod banners.
638→      let browserVersionLine: string | undefined
639→
640→      try {
641→        if (browserBinaryLocation && fs.existsSync(browserBinaryLocation)) {
642→          const vLine = getBrowserVersionLine(browserBinaryLocation)
643→          if (vLine && vLine.trim().length > 0) {
644→            browserVersionLine = vLine.trim()
645→          }
646→        }
647→      } catch {
648→        // ignore – banner will fall back to generic browser label
649→      }
650→
651→      const mode = (compilation?.options?.mode || 'development') as string
652→
653→      // Always print a manifest-based production summary once,
654→      // even if CDP fails later. CDP will attempt to "upgrade" this when it succeeds.
655→      try {
656→        if (mode === 'production') {
657→          const loadExtensionFlag = chromiumConfig.find((flag: string) =>
658→            flag.startsWith('--load-extension=')
659→          )
660→          const extensionOutputPath = getExtensionOutputPath(
661→            compilation,
662→            loadExtensionFlag
663→          )
664→
665→          if (extensionOutputPath) {
666→            await printProdBannerOnce({
667→              browser: this.options.browser,
668→              outPath: extensionOutputPath,
669→              browserVersionLine
670→            })
671→          }
672→        }
673→      } catch {
674→        // best-effort only; ignore banner errors
675→      }
676→
677→      const cdpConfig: ChromiumPluginRuntime = {
678→        ...pickSharedBrowserRuntimeOptions({
679→          ...this.options,
680→          extension: extensionsToLoad
681→        }),
682→        chromiumBinary: this.options.chromiumBinary,
683→        bannerPrintedOnce: false,
684→        cdpController: undefined,
685→        browserVersionLine
686→      }
687→
688→      // Optional CDP wiring (dev + inspection). Run-only preview disables this
689→      // to avoid pulling in WS/CDP dependencies.
690→      if (enableCdp) {
691→        const mod = await import('./setup-cdp-after-launch')
692→        await mod.setupCdpAfterLaunch(
693→          compilation,
694→          cdpConfig,
695→          chromiumConfig,
696→          pipeStreams
697→        )
698→
699→        if (cdpConfig.cdpController) {
700→          this.ctx.setController(
701→            cdpConfig.cdpController as CDPExtensionController,
702→            selectedPort
703→          )
704→        }
705→      }
706→    } catch (error) {
707→      if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
708→        console.warn('[browser] CDP post-launch setup failed:', String(error))
709→      }
710→    }
711→  }
712→
713→  private async launchWithDirectSpawn(
714→    binary: string,
715→    chromeFlags: string[],
716→    usePipe: boolean = false
717→  ) {
718→    if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
719→      this.logger.info(messages.chromeInitializingEnhancedReload())
720→    }
721→    const launchArgs = this.options?.startingUrl
722→      ? [...chromeFlags, this.options.startingUrl]
723→      : [...chromeFlags]
724→
725→    // When using --remote-debugging-pipe, Chrome communicates via fds 3 & 4.
726→    // stdio indices: 0=stdin, 1=stdout, 2=stderr, 3=pipe-write, 4=pipe-read
727→    const stdio: import('child_process').StdioOptions = usePipe
728→      ? ['ignore', 'ignore', 'ignore', 'pipe', 'pipe']
729→      : 'ignore'
730→
731→    const normalizedBinary = normalizeBinaryPathForWsl(binary)
732→
733→    try {
734→      const child = await spawnChromiumProcess({
735→        binary: normalizedBinary,
736→        launchArgs,
737→        stdio,
738→        browser: this.options.browser,
739→        logger: this.logger
740→      })
741→
742→      if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
743→        this.logger.debug?.(
744→          '[browser] Final Chrome flags:',
745→          launchArgs.join(' ')
746→        )
747→      }
748→
749→      let disposeSignalHandlers: (() => void) | undefined
750→
751→      child.on('close', (code: number | null) => {
752→        if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
753→          this.logger.info(messages.chromeProcessExited(code || 0))
754→        }
755→        disposeSignalHandlers?.()
756→
757→        const userDataDir = launchArgs
758→          .find((arg) => arg.startsWith('--user-data-dir='))
759→          ?.slice('--user-data-dir='.length)
760→          .replace(/^"|"$/g, '')
761→        utils.removeManagedEphemeralProfile(userDataDir)
762→      })
763→
764→      child.on('error', (error) => {
765→        this.logger.error(messages.chromeProcessError(error))
766→      })
767→
768→      disposeSignalHandlers = setupProcessSignalHandlers(
769→        this.options?.browser,
770→        child,
771→        () => {}
772→      )
773→
774→      return child
775→    } catch (error) {
776→      this.logger.error(messages.chromeFailedToSpawn(error))
777→      throw error
778→    }
779→  }
780→
781→  private printEnhancedPuppeteerInstallHint(
782→    compilation: CompilationLike,
783→    raw: string,
784→    browserName?: string
785→  ) {
786→    try {
787→      const displayCacheDir =
788→        binariesResolver.computeBinariesBaseDir(compilation)
789→      const pretty = messages.prettyPuppeteerInstallGuidance(
790→        (browserName as any) || (this.options?.browser as any),
791→        raw,
792→        displayCacheDir
793→      )
794→      console.error(pretty)
795→    } catch {
796→      try {
797→        const pretty = messages.prettyPuppeteerInstallGuidance(
798→          (browserName as any) || (this.options?.browser as any),
799→          raw,
800→          ''
801→        )
802→        console.error(pretty)
803→      } catch {
804→        console.error(raw)
805→      }
806→    }
807→  }
