1500→      console.warn(messages.sourceInspectorCannotReconnect())
1501→    } catch (error) {
1502→      console.error(
1503→        messages.sourceInspectorReconnectionFailed((error as Error).message)
1504→      )
1505→    }
1506→  }
1507→
1508→  // For the user: print the HTML inspection result
1509→  async printHTML(html: string) {
1510→    await this.emitSourceOutput(html, 'post_injection')
1511→  }
1512→
1513→  // Only for development: print updated HTML after file change
1514→  async printUpdatedHTML(html: string) {
1515→    await this.emitSourceOutput(html, 'updated')
1516→  }
1517→
1518→  async cleanup(): Promise<void> {
1519→    try {
1520→      if (this.isAuthorMode()) {
1521→        this.stopWatching()
1522→      }
1523→
1524→      if (this.cdpClient && this.currentTargetId) {
1525→        await this.cdpClient.closeTarget(this.currentTargetId)
1526→      }
1527→
1528→      if (this.cdpClient) {
1529→        this.cdpClient.disconnect()
1530→      }
1531→
1532→      if (this.isAuthorMode()) {
1533→        console.log(messages.sourceInspectorCleanupComplete())
1534→      }
1535→    } catch (error) {
1536→      if (this.isAuthorMode()) {
1537→        console.error(
1538→          messages.sourceInspectorCleanupError((error as Error).message)
1539→        )
1540→      }
1541→    }
1542→  }
1543→
1544→  // The only thing relevant for the user: how to get the inspection data
1545→  apply(compiler: any) {
1546→    if (!this.devOptions.source && !this.devOptions.watchSource) {
1547→      return
1548→    }
1549→    this.runtimeMode = compiler.options.mode || this.runtimeMode
1550→
1551→    compiler.hooks.done.tapPromise(
1552→      'setup-chrome-inspection',
1553→      async (stats: any) => {
1554→        try {
1555→          if (!this.isInitialized) {
1556→            await this.initialize()
1557→          }
1558→
1559→          // User: to see the real inspection data,
1560→          // provide --source <url> or --starting-url <url>
1561→          let urlToInspect: string
1562→
1563→          if (
1564→            this.devOptions.source &&
1565→            typeof this.devOptions.source === 'string' &&
1566→            this.devOptions.source !== 'true'
1567→          ) {
1568→            urlToInspect = this.devOptions.source
1569→          } else if (this.devOptions.startingUrl) {
1570→            urlToInspect = this.devOptions.startingUrl
1571→          } else {
1572→            throw new Error(messages.sourceInspectorUrlRequired())
1573→          }
1574→
1575→          // Watch mode should inspect once, then let the live watcher own updates.
1576→          const webSocketServer = (compiler.options as any).webSocketServer
1577→          if (this.devOptions.watchSource && this.hasInspectedSourceOnce) {
1578→            if (webSocketServer) {
1579→              if (!this.isWatching) {
1580→                await this.startWatching(webSocketServer)
1581→              }
1582→              return
1583→            }
1584→            if (this.currentSessionId) {
1585→              if (
1586→                (globalThis as any).__EXTJS_PENDING_CHROMIUM_CONTENT_RELOAD__
1587→              ) {
1588→                return
1589→              }
1590→              const previousRootMeta = await this.getExtensionRootMeta()
1591→              this.scheduleWatchSourceUpdate(previousRootMeta)
1592→              return
1593→            }
1594→          }
1595→
1596→          // This is the main output for the user:
1597→          const html = await this.inspectSource(urlToInspect, {
1598→            forceNavigate:
1599→              this.devOptions.watchSource && this.hasInspectedSourceOnce
1600→          })
1601→          this.hasInspectedSourceOnce = true
1602→          await this.printHTML(html)
1603→
1604→          // Watch mode is only for development
1605→          if (this.devOptions.watchSource) {
1606→            this.registerContentReloadSnapshotHook()
1607→            if (webSocketServer) {
1608→              await this.startWatching(webSocketServer)
1609→            } else {
1610→              // Fallback: reuse the attached tab when a source websocket is unavailable.
1611→              try {
1612→                const previousRootMeta = await this.getExtensionRootMeta()
1613→                if (this.currentSessionId) {
1614→                  await this.emitUpdatedSnapshotFromCurrentSession(
1615→                    this.currentSessionId,
1616→                    previousRootMeta
1617→                  )
1618→                }
1619→              } catch {
1620→                // ignore best-effort fallback
1621→              }
1622→            }
1623→          }
1624→        } catch (error) {
1625→          if (process.env.EXTENSION_AUTHOR_MODE === 'true') {
1626→            console.error(
1627→              messages.sourceInspectorSetupFailed((error as Error).message)
1628→            )
1629→          }
1630→        }
1631→      }
1632→    )
1633→  }
1634→}
