export interface ChromiumLogger {
  level?: LogLevel | 'off' | string
  contexts?: string[]
  urlFilter?: string
  tabFilter?: number | string
  format?: 'pretty' | 'json' | 'ndjson' | string
  timestamps?: boolean
  color?: boolean
}

// ─── CDP wire shapes ────────────────────────────────────────────────

/**
 * Shape returned by `Target.getTargets` → `targetInfos[]`.
 * Fields are optional because CDP does not guarantee every field on every
 * target type, but the properties used by this codebase are declared here
 * so accesses compile-check instead of going through `any`.
 */
export interface CdpTargetInfo {
  targetId?: string
  type?: string
  title?: string
  url?: string
  attached?: boolean
  browserContextId?: string
}

/**
 * Recursive DOM node returned by `DOM.getDocument` (depth: -1, pierce: true).
 */
export interface CdpDomNode {
  nodeId?: number
  localName?: string
  nodeName?: string
  nodeType?: number
  children?: CdpDomNode[]
  shadowRoots?: Array<CdpDomNode & {shadowRootType?: string}>
  contentDocument?: CdpDomNode
}

/**
 * Execution context emitted by `Runtime.executionContextCreated`.
 */
export interface CdpExecutionContext {
  id?: number
  origin?: string
  name?: string
  auxData?: {
    type?: string
    isDefault?: boolean
    frameId?: string
  }
}

/**
 * Raw CDP protocol message shape (events and command responses share this
 * envelope but with disjoint optional keys).
 */
export interface CdpProtocolMessage extends Record<string, unknown> {
  method?: string
  params?: Record<string, unknown>
  sessionId?: string
  id?: number
  result?: unknown
  error?: unknown
}

// ─── Rspack / bundler interop shapes ────────────────────────────────

/**
 * Minimal subset of a Rspack / Webpack `Compiler` consumed by plugin
 * `apply()` methods. Only the hooks and options actually read are declared.
 */
export interface RspackCompiler {
  options: {
    mode?: string
    output?: {path?: string}
    context?: string
    webSocketServer?: unknown
  }
  hooks: {
    done: {
      tapPromise: (
        name: string,
        fn: (stats: RspackStats) => Promise<void>
      ) => void
    }
  }
  getInfrastructureLogger?: (name: string) => BrowserLogger
}

/**
 * Minimal `Stats` object passed to `hooks.done` callbacks.
 */
export interface RspackStats {
  hasErrors?: () => boolean
  compilation: import('../browsers-types').CompilationLike
}

// ─── Structured return shapes (replace `any`) ───────────────────────

/** Shape returned by the extension-root-tree evaluation. */
export interface ExtensionRootTreeNode {
  tag: string
  id?: string
  classes?: string
  role?: string
  ariaLabel?: string
  textLength: number
  childCount: number
  children?: ExtensionRootTreeNode[]
}

export interface ExtensionRootTree {
  rootMode: 'shadow' | 'element'
  depthLimit: number
  nodeLimit: number
  truncated: boolean
  tree: ExtensionRootTreeNode | null
}

/** Shape returned by the page-meta snapshot evaluation. */
export interface PageMetaSnapshot {
  readyState?: string
  viewport?: {width: number; height: number; devicePixelRatio: number}
  frameCount?: number
}

/** Console counts bucket — keys are the canonical levels. */
export type ConsoleCountKey = 'error' | 'warn' | 'info' | 'log' | 'debug'

