        // Only print unified CDP logs when user has enabled verbose output
        if (String(process.env.EXTENSION_VERBOSE || '').trim() === '1') {
          const ts = new Date().toISOString()
          console.log(
            messages.cdpUnifiedExtensionLog(ts, (message as any).params)
          )
        }
      }
